{
  "name": "Smart P&L Analyst",
  "description": "A sophisticated Profit & Loss management tool that transforms financial data into actionable insights using AI. Track revenue, manage expenses, and visualize your business health with beautiful charts and automated financial analysis."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type EntryType = 'Revenue' | 'Expense';

export interface PLEntry {
  id: string;
  category: string;
  type: EntryType;
  amount: number;
  date: string;
  description: string;
}

export interface PLSummary {
  totalRevenue: number;
  totalExpense: number;
  grossProfit: number;
  netIncome: number;
  profitMargin: number;
}

export interface MonthlyData {
  month: string;
  revenue: number;
  expense: number;
  profit: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { PLEntry } from "../types";

export const analyzeFinancials = async (entries: PLEntry[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summaryString = entries.map(e => 
    `${e.date}: ${e.type} - ${e.category} ($${e.amount}) - ${e.description}`
  ).join('\n');

  const prompt = `
    As a world-class financial analyst, analyze the following Profit & Loss data and provide strategic insights:

    ${summaryString}

    Provide the analysis in a structured JSON format with the following fields:
    1. executiveSummary: A brief overview of current financial health.
    2. keyInsights: An array of strings highlighting major trends or issues.
    3. optimizationTips: An array of specific actions to improve profitability.
    4. riskFactors: Potential financial risks identified.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: { type: Type.STRING },
            keyInsights: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            optimizationTips: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            riskFactors: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["executiveSummary", "keyInsights", "optimizationTips", "riskFactors"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React from 'react';

interface FinancialCardProps {
  title: string;
  value: string;
  change?: string;
  trend?: 'up' | 'down' | 'neutral';
  color: 'blue' | 'green' | 'red' | 'indigo';
}

const FinancialCard: React.FC<FinancialCardProps> = ({ title, value, change, trend, color }) => {
  const colorClasses = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    green: 'bg-emerald-50 text-emerald-700 border-emerald-100',
    red: 'bg-rose-50 text-rose-700 border-rose-100',
    indigo: 'bg-indigo-50 text-indigo-700 border-indigo-100',
  };

  return (
    <div className={`p-6 rounded-2xl border ${colorClasses[color]} shadow-sm transition-all hover:shadow-md`}>
      <h3 className="text-sm font-semibold uppercase tracking-wider opacity-80 mb-2">{title}</h3>
      <div className="text-3xl font-bold mb-1">{value}</div>
      {change && (
        <div className={`text-xs font-medium flex items-center ${
          trend === 'up' ? 'text-emerald-600' : trend === 'down' ? 'text-rose-600' : 'text-slate-500'
        }`}>
          {trend === 'up' && '▲'} {trend === 'down' && '▼'} {change} from last period
        </div>
      )}
    </div>
  );
};

export default FinancialCard;

import React, { useState } from 'react';
import { EntryType, PLEntry } from '../types';

interface EntryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: Omit<PLEntry, 'id'>) => void;
}

const EntryModal: React.FC<EntryModalProps> = ({ isOpen, onClose, onSave }) => {
  const [formData, setFormData] = useState({
    category: '',
    type: 'Revenue' as EntryType,
    amount: '',
    date: new Date().toISOString().split('T')[0],
    description: ''
  });

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...formData,
      amount: parseFloat(formData.amount) || 0
    });
    setFormData({
      category: '',
      type: 'Revenue',
      amount: '',
      date: new Date().toISOString().split('T')[0],
      description: ''
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-xl font-bold text-slate-800">New Entry</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Type</label>
            <div className="grid grid-cols-2 gap-2">
              <button
                type="button"
                onClick={() => setFormData({...formData, type: 'Revenue'})}
                className={`py-2 rounded-lg text-sm font-semibold transition-all ${formData.type === 'Revenue' ? 'bg-emerald-100 text-emerald-700 border-2 border-emerald-500' : 'bg-slate-50 text-slate-500 border border-slate-200'}`}
              >
                Revenue
              </button>
              <button
                type="button"
                onClick={() => setFormData({...formData, type: 'Expense'})}
                className={`py-2 rounded-lg text-sm font-semibold transition-all ${formData.type === 'Expense' ? 'bg-rose-100 text-rose-700 border-2 border-rose-500' : 'bg-slate-50 text-slate-500 border border-slate-200'}`}
              >
                Expense
              </button>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
            <input
              type="text"
              required
              placeholder="e.g. Sales, Rent, Marketing"
              className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={formData.category}
              onChange={e => setFormData({...formData, category: e.target.value})}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Amount ($)</label>
              <input
                type="number"
                required
                placeholder="0.00"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Date</label>
              <input
                type="date"
                required
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Description (Optional)</label>
            <textarea
              rows={2}
              className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            />
          </div>

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.98] transition-all"
          >
            Add Transaction
          </button>
        </form>
      </div>
    </div>
  );
};

export default EntryModal;

import React, { useState, useMemo, useEffect } from 'react';
import { PLEntry, PLSummary, MonthlyData } from './types';
import FinancialCard from './components/FinancialCard';
import EntryModal from './components/EntryModal';
import { analyzeFinancials } from './services/geminiService';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: 'Product Sales', type: 'Revenue', amount: 15000, date: '2024-01-15', description: 'Core product sales' },
  { id: '2', category: 'Consulting', type: 'Revenue', amount: 5000, date: '2024-01-20', description: 'B2B Services' },
  { id: '3', category: 'Rent', type: 'Expense', amount: 3000, date: '2024-01-01', description: 'Office lease' },
  { id: '4', category: 'Marketing', type: 'Expense', amount: 1200, date: '2024-01-10', description: 'Social media ads' },
  { id: '5', category: 'Salaries', type: 'Expense', amount: 8000, date: '2024-01-28', description: 'Full-time staff' },
];

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === 'Revenue').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = entries.filter(e => e.type === 'Expense').reduce((acc, curr) => acc + curr.amount, 0);
    const profit = revenue - expense;
    return {
      totalRevenue: revenue,
      totalExpense: expense,
      grossProfit: profit,
      netIncome: profit, // Simple model
      profitMargin: revenue > 0 ? (profit / revenue) * 100 : 0
    };
  }, [entries]);

  const monthlyChartData = useMemo(() => {
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
    return months.map(m => {
      // Mock historical data + actual current data
      const monthIndex = months.indexOf(m);
      if (m === 'Jan') {
        return { 
          month: m, 
          revenue: summary.totalRevenue, 
          expense: summary.totalExpense, 
          profit: summary.grossProfit 
        };
      }
      return {
        month: m,
        revenue: Math.random() * 20000 + 10000,
        expense: Math.random() * 10000 + 5000,
        profit: 0
      };
    }).map(d => ({...d, profit: d.revenue - d.expense}));
  }, [summary]);

  const expenseBreakdown = useMemo(() => {
    const map = new Map<string, number>();
    entries.filter(e => e.type === 'Expense').forEach(e => {
      map.set(e.category, (map.get(e.category) || 0) + e.amount);
    });
    return Array.from(map.entries()).map(([name, value]) => ({ name, value }));
  }, [entries]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    const entryWithId = { ...newEntry, id: Math.random().toString(36).substr(2, 9) };
    setEntries(prev => [...prev, entryWithId]);
  };

  const handleRunAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const analysis = await analyzeFinancials(entries);
      setAiAnalysis(analysis);
    } catch (err) {
      alert("Failed to analyze data. Please check your API key.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const deleteEntry = (id: string) => {
    setEntries(prev => prev.filter(e => e.id !== id));
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">P</div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart P&L Analyst</h1>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={handleRunAiAnalysis}
              disabled={isAnalyzing}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-xl font-semibold hover:bg-indigo-100 transition-all disabled:opacity-50"
            >
              {isAnalyzing ? (
                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                </svg>
              ) : (
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              )}
              AI Insights
            </button>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:-translate-y-0.5 transition-all active:translate-y-0"
            >
              Add Entry
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 pt-8">
        {/* KPI Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <FinancialCard 
            title="Total Revenue" 
            value={`$${summary.totalRevenue.toLocaleString()}`} 
            color="blue" 
            change="12.5%" 
            trend="up" 
          />
          <FinancialCard 
            title="Total Expenses" 
            value={`$${summary.totalExpense.toLocaleString()}`} 
            color="red" 
            change="3.1%" 
            trend="up" 
          />
          <FinancialCard 
            title="Net Income" 
            value={`$${summary.netIncome.toLocaleString()}`} 
            color="green" 
            change="8.4%" 
            trend="up" 
          />
          <FinancialCard 
            title="Profit Margin" 
            value={`${summary.profitMargin.toFixed(1)}%`} 
            color="indigo" 
            change="2.3%" 
            trend="up" 
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          {/* Main Chart */}
          <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Revenue vs Expenses (6M Forecast)</h3>
            <div className="h-80">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={monthlyChartData}>
                  <defs>
                    <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                    </linearGradient>
                    <linearGradient id="colorExp" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <Tooltip 
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                  />
                  <Area type="monotone" dataKey="revenue" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                  <Area type="monotone" dataKey="expense" stroke="#f43f5e" strokeWidth={3} fillOpacity={1} fill="url(#colorExp)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Expense Breakdown */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Expense Distribution</h3>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={expenseBreakdown}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {expenseBreakdown.map((_, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend verticalAlign="bottom" height={36} />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>

        {/* AI Analysis View */}
        {aiAnalysis && (
          <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-3xl p-8 mb-8 text-white shadow-xl animate-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center gap-3 mb-6">
              <div className="bg-white/20 p-2 rounded-lg">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </div>
              <h2 className="text-2xl font-bold">AI Strategic Analysis</h2>
            </div>

            <p className="text-indigo-50 text-lg mb-8 leading-relaxed max-w-4xl">
              {aiAnalysis.executiveSummary}
            </p>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="bg-white/10 backdrop-blur-md p-6 rounded-2xl border border-white/10">
                <h4 className="font-bold text-lg mb-4 flex items-center gap-2">
                  <span className="w-2 h-6 bg-amber-400 rounded-full"></span> Key Insights
                </h4>
                <ul className="space-y-3 opacity-90 text-sm">
                  {aiAnalysis.keyInsights.map((item: string, i: number) => (
                    <li key={i} className="flex gap-2">
                      <span className="text-amber-400">•</span> {item}
                    </li>
                  ))}
                </ul>
              </div>

              <div className="bg-white/10 backdrop-blur-md p-6 rounded-2xl border border-white/10">
                <h4 className="font-bold text-lg mb-4 flex items-center gap-2">
                  <span className="w-2 h-6 bg-emerald-400 rounded-full"></span> Optimization
                </h4>
                <ul className="space-y-3 opacity-90 text-sm">
                  {aiAnalysis.optimizationTips.map((item: string, i: number) => (
                    <li key={i} className="flex gap-2">
                      <span className="text-emerald-400">→</span> {item}
                    </li>
                  ))}
                </ul>
              </div>

              <div className="bg-white/10 backdrop-blur-md p-6 rounded-2xl border border-white/10">
                <h4 className="font-bold text-lg mb-4 flex items-center gap-2">
                  <span className="w-2 h-6 bg-rose-400 rounded-full"></span> Risk Factors
                </h4>
                <ul className="space-y-3 opacity-90 text-sm">
                  {aiAnalysis.riskFactors.map((item: string, i: number) => (
                    <li key={i} className="flex gap-2 text-rose-100">
                      <span className="text-rose-300">!</span> {item}
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        )}

        {/* Transaction Table */}
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center">
            <h3 className="text-lg font-bold text-slate-800">Recent Transactions</h3>
            <div className="flex gap-2">
              <button className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
              </button>
              <button className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              </button>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <th className="px-6 py-4">Date</th>
                  <th className="px-6 py-4">Category</th>
                  <th className="px-6 py-4">Description</th>
                  <th className="px-6 py-4">Type</th>
                  <th className="px-6 py-4 text-right">Amount</th>
                  <th className="px-6 py-4 text-center">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {entries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(entry => (
                  <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 text-sm text-slate-600">{entry.date}</td>
                    <td className="px-6 py-4 font-semibold text-slate-800">{entry.category}</td>
                    <td className="px-6 py-4 text-sm text-slate-500">{entry.description || '-'}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-tighter ${
                        entry.type === 'Revenue' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'
                      }`}>
                        {entry.type}
                      </span>
                    </td>
                    <td className={`px-6 py-4 text-right font-bold ${
                      entry.type === 'Revenue' ? 'text-emerald-600' : 'text-slate-700'
                    }`}>
                      {entry.type === 'Revenue' ? '+' : '-'}${entry.amount.toLocaleString()}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <button 
                        onClick={() => deleteEntry(entry.id)}
                        className="p-2 text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {entries.length === 0 && (
            <div className="p-12 text-center text-slate-400">
              No transactions yet. Click "Add Entry" to get started.
            </div>
          )}
        </div>
      </main>

      <EntryModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleAddEntry} 
      />
    </div>
  );
};

export default App;

export type EntryType = '매출' | '지출';

export type CategoryType = '식자재' | '인건비' | '월세' | '관리비' | '비고정지출' | '판매수수료' | '기타매출';

export interface PLEntry {
  id: string;
  category: string;
  type: EntryType;
  amount: number;
  date: string;
  description: string;
}

export interface PLSummary {
  totalRevenue: number;
  totalExpense: number;
  netProfit: number;
  foodCostRatio: number;
  laborCostRatio: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { PLEntry } from "../types";

export const analyzeFinancials = async (entries: PLEntry[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summaryString = entries.map(e => 
    `${e.date}: [${e.type}] ${e.category} - ${e.amount.toLocaleString()}원 (${e.description})`
  ).join('\n');

  const prompt = `
    당신은 대한민국 최고의 식당 경영 컨설턴트입니다. 다음은 어느 식당의 최근 손익 데이터입니다:

    ${summaryString}

    이 데이터를 바탕으로 식당 사장님께 드릴 전문적인 분석 보고서를 JSON 형식으로 작성하세요. 
    특히 '식자재비 비율(Food Cost %)', '인건비 비중', '고정비 부담' 등을 중점적으로 분석하세요.

    응답 형식(JSON):
    1. executiveSummary: 현재 식당의 전반적인 재무 상태 요약 (사장님께 격려의 말 포함).
    2. keyInsights: 현재 데이터에서 발견된 주요 특징 3가지 (예: 식자재비 과다, 주말 매출 집중 등).
    3. optimizationTips: 수익성을 높이기 위한 구체적인 액션 아이템 3가지.
    4. riskFactors: 주의해야 할 잠재적 위험 요소.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: { type: Type.STRING },
            keyInsights: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            optimizationTips: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            riskFactors: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["executiveSummary", "keyInsights", "optimizationTips", "riskFactors"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

