  { id: '3', category: '인건비', type: '지출', amount: 150000, date: '2024-05-20', description: '주방 알바 일급' },
  { id: '4', category: '관리비', type: '지출', amount: 80000, date: '2024-05-19', description: '수도세 분할' },
  { id: '5', category: '배달매출', type: '매출', amount: 350000, date: '2024-05-20', description: '배민/쿠팡이츠' },
];

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#475569'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = entries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const foodCost = entries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);
    const laborCost = entries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0);

    return {
      totalRevenue: revenue,
      totalExpense: expense,
      netProfit: revenue - expense,
      foodCostRatio: revenue > 0 ? (foodCost / revenue) * 100 : 0,
      laborCostRatio: revenue > 0 ? (laborCost / revenue) * 100 : 0
    };
  }, [entries]);

  const dailyChartData = useMemo(() => {
    const last7Days = Array.from({length: 7}, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();

    return last7Days.map(date => {
      const dayEntries = entries.filter(e => e.date === date);
      const rev = dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
      const exp = dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
      return { 
        date: date.slice(5), 
        매출: rev, 
        지출: exp,
        수익: rev - exp
      };
    });
  }, [entries]);

  const expenseBreakdown = useMemo(() => {
    const map = new Map<string, number>();
    entries.filter(e => e.type === '지출').forEach(e => {
      map.set(e.category, (map.get(e.category) || 0) + e.amount);
    });
    return Array.from(map.entries()).map(([name, value]) => ({ name, value }));
  }, [entries]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    const entryWithId = { ...newEntry, id: Math.random().toString(36).substr(2, 9) };
    setEntries(prev => [...prev, entryWithId]);
  };

  const handleRunAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const analysis = await analyzeFinancials(entries);
      setAiAnalysis(analysis);
    } catch (err) {
      alert("AI 분석 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const deleteEntry = (id: string) => {
    if(confirm('이 내역을 삭제할까요?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  return (
    <div className="min-h-screen bg-[#fcfcfd] pb-20">
