                    <td className={`px-6 py-4 text-right font-black text-sm ${
                      entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'
                    }`}>
                      {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                    </td>
                    <td className="px-4 py-4 text-right">
                      <button 
                        onClick={() => deleteEntry(entry.id)}
                        className="p-2 text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"
                      >
