} from 'recharts';

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1200000, date: '2024-05-20', description: '평일 점심/저녁' },
  { id: '2', category: '식자재', type: '지출', amount: 450000, date: '2024-05-20', description: '정육 및 채소 매입' },
  { id: '3', category: '인건비', type: '지출', amount: 150000, date: '2024-05-20', description: '주방 알바 일급' },
  { id: '4', category: '관리비', type: '지출', amount: 80000, date: '2024-05-19', description: '수도세 분할' },
  { id: '5', category: '배달매출', type: '매출', amount: 350000, date: '2024-05-20', description: '배민/쿠팡이츠' },
];

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#475569'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = entries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const foodCost = entries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);
    const laborCost = entries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0);

    return {
      totalRevenue: revenue,
      totalExpense: expense,
      netProfit: revenue - expense,
      foodCostRatio: revenue > 0 ? (foodCost / revenue) * 100 : 0,
      laborCostRatio: revenue > 0 ? (laborCost / revenue) * 100 : 0
    };
  }, [entries]);

  const dailyChartData = useMemo(() => {
    const dates = Array.from(new Set(entries.map(e => e.date))).sort();
    return dates.slice(-7).map(date => {
      const dayEntries = entries.filter(e => e.date === date);
      const rev = dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
      const exp = dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
      return { date: date.slice(5), 매출: rev, 지출: exp };
    });
  }, [entries]);

  const expenseBreakdown = useMemo(() => {
    const map = new Map<string, number>();
    entries.filter(e => e.type === '지출').forEach(e => {
      map.set(e.category, (map.get(e.category) || 0) + e.amount);
    });
    return Array.from(map.entries()).map(([name, value]) => ({ name, value }));
  }, [entries]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...newEntry, id: Math.random().toString(36).substr(2, 9) }]);
  };

  const handleRunAiAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const analysis = await analyzeFinancials(entries);
      setAiAnalysis(analysis);
    } catch (err) {
      alert("AI 분석 오류가 발생했습니다.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const result = await analyzeReceipt(base64, file.type);

        // 스캔 결과로 내역 추가 (사용자 확인 단계는 생략하고 즉시 추가하거나 모달을 띄울 수 있음)
        // 여기선 사용자 편의를 위해 즉시 추가함
        handleAddEntry({
          ...result,
          amount: result.amount || 0,
          date: result.date || new Date().toISOString().split('T')[0]
        });
        alert(`${result.description} (${result.amount.toLocaleString()}원) 내역이 자동 추가되었습니다.`);
      };
    } catch (err) {
      alert("영수증 스캔 중 오류가 발생했습니다.");
    } finally {
      setIsScanning(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-[#fcfcfd] pb-20">
      <nav className="bg-white border-b border-slate-100 sticky top-0 z-40 px-4 py-3">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-slate-900 rounded-2xl flex items-center justify-center text-white">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <div>
              <h1 className="text-lg font-black text-slate-900 leading-tight">식당 손익 매니저</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">AI 자동 지출 정리</p>
            </div>
          </div>
          <div className="flex gap-2">
            <input 
              type="file" 
              accept="image/*" 
              capture="environment" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileChange}
            />
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={isScanning}
              className="bg-emerald-50 text-emerald-700 border border-emerald-100 px-4 py-2.5 rounded-2xl font-bold shadow-sm hover:bg-emerald-100 transition-all flex items-center gap-2"
            >
              {isScanning ? (
                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              )}
              스캔
            </button>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="bg-indigo-600 text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
              추가
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 pt-8">
        {/* KPI Cards */}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <FinancialCard title="총 매출" value={`${summary.totalRevenue.toLocaleString()}원`} color="blue" />
          <FinancialCard title="총 지출" value={`${summary.totalExpense.toLocaleString()}원`} color="red" />
          <FinancialCard title="순수익" value={`${summary.netProfit.toLocaleString()}원`} color="green" />
          <div className="p-4 rounded-2xl border bg-white shadow-sm flex flex-col justify-center">
            <h3 className="text-[10px] font-bold text-slate-400 mb-1 uppercase tracking-tighter">주요 비율</h3>
            <div className="space-y-1">
              <div className="flex justify-between text-xs">
                <span className="text-slate-500">식자재</span>
                <span className="font-bold text-slate-800">{summary.foodCostRatio.toFixed(1)}%</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500">인건비</span>
                <span className="font-bold text-slate-800">{summary.laborCostRatio.toFixed(1)}%</span>
              </div>
