          </div>
        </div>

        {/* Charts Section */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          <div className="lg:col-span-2 bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-6">수익 현황</h3>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={dailyChartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f8fafc" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                  <YAxis hide />
                  <Tooltip />
                  <Area type="monotone" dataKey="매출" stroke="#6366f1" fill="#6366f1" fillOpacity={0.05} strokeWidth={3} />
                  <Area type="monotone" dataKey="지출" stroke="#f43f5e" fill="#f43f5e" fillOpacity={0.05} strokeWidth={3} />
