    응답 형식(JSON):
    1. executiveSummary: 전반적인 재무 상태 요약.
    2. keyInsights: 주요 특징 3가지.
    3. optimizationTips: 수익성 향상 팁 3가지.
    4. riskFactors: 잠재적 위험 요소.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: { type: Type.STRING },
            keyInsights: { type: Type.ARRAY, items: { type: Type.STRING } },
            optimizationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
            riskFactors: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["executiveSummary", "keyInsights", "optimizationTips", "riskFactors"]
        }
      }
    });

    // Directly access .text property as per guidelines
    const text = response.text;
    if (!text) throw new Error("AI response is empty");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

// Using gemini-3-pro-preview for OCR and image analysis
export const analyzeReceipt = async (base64Image: string, mimeType: string) => {
  const prompt = `
    이 영수증 이미지에서 다음 정보를 추출하여 JSON 형식으로 응답하세요:
    1. amount: 합계 금액 (숫자만)
    2. date: 결제일 또는 발행일 (YYYY-MM-DD 형식)
    3. category: 다음 중 가장 적절한 카테고리 하나 선택 ['식자재', '인건비', '월세', '관리비', '비고정지출', '판매수수료', '기타매출']
    4. description: 가맹점명 및 주요 품목 요약
    5. type: '지출' (기본값)
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      // Fixed: Use parts array within an object for multi-part contents
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            description: { type: Type.STRING },
            type: { type: Type.STRING }
          },
          required: ["amount", "date", "category", "description", "type"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Receipt analysis response is empty");
    return JSON.parse(text);
  } catch (error) {
    console.error("Receipt Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useMemo, useRef } from 'react';
import { PLEntry, PLSummary } from './types';
