  { id: '2', category: '식자재', type: '지출', amount: 450000, date: '2024-05-20', description: '정육 및 채소 매입' },
  { id: '3', category: '인건비', type: '지출', amount: 150000, date: '2024-05-20', description: '주방 알바 일급' },
  { id: '4', category: '관리비', type: '지출', amount: 80000, date: '2024-05-19', description: '수도세 분할' },
  { id: '5', category: '배달매출', type: '매출', amount: 350000, date: '2024-05-20', description: '배민/쿠팡이츠' },
