  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = entries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const foodCost = entries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);
    const laborCost = entries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0);

    return {
      totalRevenue: revenue,
      totalExpense: expense,
      netProfit: revenue - expense,
      foodCostRatio: revenue > 0 ? (foodCost / revenue) * 100 : 0,
      laborCostRatio: revenue > 0 ? (laborCost / revenue) * 100 : 0
    };
  }, [entries]);

  const dailyChartData = useMemo(() => {
    // Explicitly cast to string[] to prevent 'unknown' type inference on dates when using Array.from/Set
    const dates = Array.from(new Set(entries.map(e => e.date))).sort() as string[];
    return dates.slice(-7).map(date => {
      const dayEntries = entries.filter(e => e.date === date);
      const rev = dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
      const exp = dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
      return { date: date.slice(5), 매출: rev, 지출: exp };
    });
