            </div>
            <h1 className="text-lg font-black text-slate-900 hidden sm:block">식당 스마트 인건비/손익</h1>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={() => setIsStaffModalOpen(true)}
              className="bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-sm"
            >
              직원 설정
            </button>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="bg-indigo-600 text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2 text-sm"
            >
              기록하기
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 pt-8">
        {/* Profit Highlight Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-700 p-6 rounded-[2rem] text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
            <div className="absolute -right-4 -bottom-4 opacity-10">
              <svg className="w-32 h-32" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
            </div>
            <div className="relative z-10">
              <h3 className="text-indigo-100 text-xs font-bold uppercase tracking-widest mb-1">오늘의 순수익</h3>
              <div className="text-4xl font-black mb-1">{stats.todayProfit.toLocaleString()}원</div>
              <p className="text-indigo-200 text-[10px] font-medium">* 정규직 일급 {Math.round(dailyFixedLaborCost).toLocaleString()}원 반영됨</p>
