          <div className="bg-white border border-slate-100 p-6 rounded-[2rem] shadow-sm flex flex-col justify-between">
            <div>
              <h3 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">이번 달 누적 순수익 ({new Date().getMonth() + 1}월)</h3>
              <div className="text-4xl font-black text-slate-800">{stats.monthProfit.toLocaleString()}원</div>
            </div>
            <div className="flex gap-4 mt-4 pt-4 border-t border-slate-50">
              <div>
                <span className="text-[10px] text-slate-400 font-bold block">월 매출액</span>
                <span className="text-sm font-bold text-indigo-600">+{stats.monthRev.toLocaleString()}</span>
              </div>
              <div>
                <span className="text-[10px] text-slate-400 font-bold block">월 지출액</span>
