          <FinancialCard title="누적 순수익" value={`${summary.netProfit.toLocaleString()}원`} color="green" />
          <div className="p-4 rounded-2xl border bg-white shadow-sm flex flex-col justify-center">
            <h3 className="text-[10px] font-bold text-slate-400 mb-1 uppercase tracking-tighter">인건비 비중</h3>
            <div className="text-xl font-black text-slate-800">{summary.laborCostRatio.toFixed(1)}%</div>
            <p className="text-[9px] text-slate-400">전체 매출 대비 인건비 비율</p>
