                    <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip />
                    <Area type="monotone" dataKey="매출" stroke="#6366f1" fill="#6366f1" fillOpacity={0.05} strokeWidth={3} />
                    <Area type="monotone" dataKey="지출" stroke="#f43f5e" fill="#f43f5e" fillOpacity={0.05} strokeWidth={3} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Recent Table */}
            <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-slate-50 flex justify-between items-center">
                <h3 className="font-bold text-slate-800">최근 기록 내역</h3>
                <span className="text-[10px] text-slate-400 font-bold uppercase">{entries.length}개의 내역</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 text-slate-400 text-[10px] font-bold uppercase tracking-widest">
                    <tr>
                      <th className="px-6 py-4">날짜</th>
                      <th className="px-6 py-4">카테고리</th>
                      <th className="px-6 py-4">내용</th>
                      <th className="px-6 py-4 text-right">금액</th>
                      <th className="px-6 py-4 text-center w-20">관리</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                      <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="px-6 py-4 text-xs text-slate-400">{entry.date.slice(5)}</td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-lg text-[10px] font-bold ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-100 text-slate-600'}`}>
                            {entry.category}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-sm font-medium text-slate-700">{entry.description}</td>
                        <td className={`px-6 py-4 text-right font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                          {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)}
                            className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                            title="내역 삭제"
                          >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                          </button>
                        </td>
                      </tr>
                    ))}
                    {entries.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-slate-400 text-sm">
                          기록된 내역이 없습니다.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 text-white p-6 rounded-3xl shadow-xl">
              <h3 className="font-bold text-sm mb-4">현재 등록 직원 ({staffList.length}명)</h3>
              <div className="space-y-3">
                {staffList.map(s => (
                  <div key={s.id} className="flex items-center justify-between bg-white/10 p-3 rounded-2xl">
                    <div>
                      <div className="font-bold text-sm">{s.name}</div>
                      <div className="text-[10px] text-slate-400">{s.type === '정규직' ? `월 ${s.basePay.toLocaleString()}원` : `시급 ${s.basePay.toLocaleString()}원`}</div>
                    </div>
                    <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${s.type === '정규직' ? 'bg-blue-500/20 text-blue-300' : 'bg-orange-500/20 text-orange-300'}`}>
                      {s.type}
                    </span>
                  </div>
                ))}
              </div>
            </div>

            {aiAnalysis && (
              <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-3xl">
                <h4 className="font-black text-indigo-900 text-xs mb-3 flex items-center gap-2">
                  <span className="w-1.5 h-1.5 bg-indigo-600 rounded-full"></span> AI 컨설팅
                </h4>
                <p className="text-xs text-indigo-700 leading-relaxed italic">"{aiAnalysis.executiveSummary}"</p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Staff Management Modal */}
      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black text-slate-800">직원 등록 및 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <form onSubmit={handleAddStaff} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-3">
                <input name="name" required placeholder="직원 성명" className="px-4 py-3 bg-slate-50 rounded-xl outline-none text-sm border border-transparent focus:border-indigo-300 focus:bg-white transition-all" />
                <select name="type" className="px-4 py-3 bg-slate-50 rounded-xl outline-none text-sm font-bold border border-transparent focus:border-indigo-300 focus:bg-white transition-all">
                  <option value="정규직">정규직(월급)</option>
                  <option value="알바">알바(시급)</option>
                </select>
              </div>
              <input name="basePay" type="number" required placeholder="급여액 (월급 또는 시급)" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none text-sm font-bold border border-transparent focus:border-indigo-300 focus:bg-white transition-all" />
              <button type="submit" className="w-full bg-slate-900 text-white py-3.5 rounded-xl font-bold hover:bg-black transition-all">등록하기</button>
            </form>

            <div className="space-y-2 max-h-48 overflow-y-auto pr-2">
              <h4 className="text-[10px] font-black text-slate-400 uppercase mb-3">등록된 직원 목록</h4>
              {staffList.map(s => (
                <div key={s.id} className="flex justify-between items-center text-sm p-3 bg-slate-50 rounded-xl">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-slate-700">{s.name}</span>
                    <span className={`text-[8px] px-1.5 py-0.5 rounded font-black ${s.type === '정규직' ? 'bg-blue-100 text-blue-600' : 'bg-orange-100 text-orange-600'}`}>{s.type}</span>
                  </div>
                  <button 
                    onClick={() => {
                      if(window.confirm(`${s.name} 직원을 삭제하시겠습니까? 관련 데이터가 영향받을 수 있습니다.`)) {
                        setStaffList(prev => prev.filter(st => st.id !== s.id));
                      }
                    }} 
                    className="text-rose-400 hover:text-rose-600 font-medium text-xs transition-colors"
                  >
                    삭제
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleAddEntry} 
        staffList={staffList}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef } from 'react';
import { PLEntry, PLSummary, Staff } from './types';
import FinancialCard from './components/FinancialCard';
import EntryModal from './components/EntryModal';
import { analyzeFinancials, analyzeReceipt } from './services/geminiService';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3000000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1200000, date: new Date().toISOString().split('T')[0], description: '평일 점심/저녁' },
  { id: '2', category: '식자재', type: '지출', amount: 450000, date: new Date().toISOString().split('T')[0], description: '정육 및 채소 매입' },
  { id: '4', category: '관리비', type: '지출', amount: 80000, date: new Date().toISOString().split('T')[0], description: '수도세 분할' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);

  // 정규직 매일 자동 발생 비용 (30일 기준)
  const dailyFixedLaborCost = useMemo(() => {
    return staffList
      .filter(s => s.type === '정규직')
      .reduce((acc, curr) => acc + (curr.basePay / 30), 0);
  }, [staffList]);

  // [추가] 인원별 인건비 누적 계산 로직
  const laborBreakdown = useMemo(() => {
    const activeDatesCount = new Set(entries.map(e => e.date)).size || 1;

    return staffList.map(staff => {
      let total = 0;
      if (staff.type === '정규직') {
        // 정규직은 데이터가 있는 날짜 수만큼 일급 합산
        total = (staff.basePay / 30) * activeDatesCount;
      } else {
        // 알바는 description에 이름이 포함된 인건비 내역 합산 (또는 staffId 매칭)
        total = entries
          .filter(e => e.category === '인건비' && e.description.includes(staff.name))
          .reduce((acc, curr) => acc + curr.amount, 0);
      }
      return { ...staff, totalAccrued: total };
    }).sort((a, b) => b.totalAccrued - a.totalAccrued);
  }, [staffList, entries]);

  const stats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const todayRev = todayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayExp = todayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + dailyFixedLaborCost;

    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));
    const monthRev = monthEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const currentDay = new Date().getDate();
    const monthExp = monthEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + (dailyFixedLaborCost * currentDay);

    return { todayProfit: todayRev - todayExp, monthProfit: monthRev - monthExp, monthRev, monthExp };
  }, [entries, dailyFixedLaborCost, todayStr, thisMonthStr]);

  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const manualExpense = entries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const activeDates = new Set(entries.map(e => e.date)).size || 1;
    const autoLaborExpense = dailyFixedLaborCost * activeDates;
    const totalExpense = manualExpense + autoLaborExpense;
    const laborCost = entries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0) + autoLaborExpense;

    return {
      totalRevenue: revenue,
      totalExpense: totalExpense,
      netProfit: revenue - totalExpense,
      foodCostRatio: revenue > 0 ? (entries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0) / revenue) * 100 : 0,
      laborCostRatio: revenue > 0 ? (laborCost / revenue) * 100 : 0
    };
  }, [entries, dailyFixedLaborCost]);

  const dailyChartData = useMemo(() => {
    const dates = Array.from(new Set(entries.map(e => e.date))).sort() as string[];
    return dates.slice(-7).map(date => {
      const dayEntries = entries.filter(e => e.date === date);
      return { 
        date: date.slice(5), 
        매출: dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0), 
        지출: dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + dailyFixedLaborCost 
      };
    });
  }, [entries, dailyFixedLaborCost]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    const entryWithId = { ...newEntry, id: `entry-${Date.now()}-${Math.random().toString(36).substr(2, 5)}` };
    setEntries(prev => [...prev, entryWithId]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까? 관련 통계에서 즉시 제외됩니다.')) {
      setEntries(prev => prev.filter(entry => entry.id !== id));
    }
  };

  const handleAddStaff = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newStaff: Staff = {
      id: `staff-${Date.now()}`,
      name: formData.get('name') as string,
      type: formData.get('type') as any,
      basePay: Number(formData.get('basePay'))
    };
    setStaffList(prev => [...prev, newStaff]);
    e.currentTarget.reset();
  };

  return (
    <div className="min-h-screen bg-[#fcfcfd] pb-24">
      <nav className="bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 px-4 py-3">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight">식당 손익 마스터</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsStaffModalOpen(true)} className="bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-sm">직원 관리</button>
            <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2 text-sm">기록하기</button>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 pt-8 space-y-8">
        {/* Profit Highlights */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-2xl shadow-indigo-200 relative overflow-hidden group">
            <div className="absolute right-0 top-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
            <div className="relative z-10">
              <h3 className="text-indigo-100 text-xs font-bold uppercase tracking-widest mb-2">오늘 예상 순수익</h3>
              <div className="text-5xl font-black mb-2 tracking-tighter">{stats.todayProfit.toLocaleString()}원</div>
              <div className="flex items-center gap-2 text-indigo-200 text-[10px] font-bold">
                <span className="px-1.5 py-0.5 bg-white/20 rounded">인건비 자동포함</span>
                <span>일일 고정비 {Math.round(dailyFixedLaborCost).toLocaleString()}원 반영</span>
              </div>
            </div>
          </div>
          <div className="bg-white border border-slate-100 p-8 rounded-[2.5rem] shadow-sm flex flex-col justify-between">
            <div>
              <h3 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-2">이번 달 누적 순수익</h3>
              <div className="text-5xl font-black text-slate-800 tracking-tighter">{stats.monthProfit.toLocaleString()}원</div>
            </div>
            <div className="flex gap-6 mt-6 pt-6 border-t border-slate-50">
              <div>
                <span className="text-[10px] text-slate-400 font-bold block uppercase mb-1">매출</span>
                <span className="text-lg font-black text-indigo-600">+{stats.monthRev.toLocaleString()}</span>
              </div>
              <div>
                <span className="text-[10px] text-slate-400 font-bold block uppercase mb-1">지출</span>
                <span className="text-lg font-black text-rose-500">-{stats.monthExp.toLocaleString()}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Labor Breakdown Section [추가된 섹션] */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden p-8">
          <div className="flex justify-between items-end mb-8">
            <div>
              <h3 className="text-xl font-black text-slate-800 mb-1">인물별 인건비 합계</h3>
              <p className="text-sm text-slate-400 font-medium">정규직 일할 계산 + 알바 기록 합산</p>
            </div>
            <div className="text-right">
              <span className="text-[10px] font-black text-slate-400 uppercase block mb-1">총 인건비 지출</span>
              <span className="text-2xl font-black text-slate-800">
                {laborBreakdown.reduce((acc, c) => acc + c.totalAccrued, 0).toLocaleString()}원
              </span>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {laborBreakdown.map(staff => (
              <div key={staff.id} className="bg-slate-50 p-5 rounded-3xl border border-slate-100 relative group transition-all hover:bg-white hover:shadow-md">
                <div className="flex justify-between items-start mb-3">
                  <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${staff.type === '정규직' ? 'bg-blue-100 text-blue-600' : 'bg-orange-100 text-orange-600'}`}>
                    {staff.type}
                  </span>
                  <span className="text-xs font-bold text-slate-400">{staff.type === '정규직' ? '고정지출' : '변동지출'}</span>
                </div>
                <div className="text-lg font-black text-slate-800 mb-1">{staff.name}</div>
                <div className="text-xl font-black text-indigo-600">{staff.totalAccrued.toLocaleString()}원</div>
                <div className="mt-3 w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
                  <div 
                    className={`h-full rounded-full ${staff.type === '정규직' ? 'bg-blue-500' : 'bg-orange-500'}`}
                    style={{ width: `${Math.min(100, (staff.totalAccrued / (summary.totalRevenue || 1)) * 100)}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h3 className="font-black text-slate-800 mb-6 flex items-center gap-2">
                <div className="w-1.5 h-6 bg-indigo-600 rounded-full"></div>
                최근 7일 수익 차트
              </h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={dailyChartData}>
                    <defs>
                      <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="매출" stroke="#6366f1" fill="url(#colorRev)" strokeWidth={4} />
                    <Area type="monotone" dataKey="지출" stroke="#f43f5e" fillOpacity={0} strokeWidth={4} strokeDasharray="8 8" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Records Table */}
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                <h3 className="font-black text-slate-800">전체 기록 내역</h3>
                <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-bold uppercase">{entries.length} Items</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-50">
                    <tr>
                      <th className="px-8 py-5">날짜</th>
