import React, { useState, useEffect } from 'react';
import { EntryType, PLEntry, CategoryType, Staff, Vendor } from '../types';

interface EntryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: Omit<PLEntry, 'id'>) => void;
  staffList: Staff[];
  vendorList: Vendor[];
}

const CATEGORIES: CategoryType[] = ['식자재', '인건비', '월세', '관리비', '비고정지출', '판매수수료', '기타매출'];

const EntryModal: React.FC<EntryModalProps> = ({ isOpen, onClose, onSave, staffList, vendorList }) => {
  const [formData, setFormData] = useState({
    category: '식자재',
    type: '지출' as EntryType,
    amount: '',
    date: new Date().toISOString().split('T')[0],
    description: '',
    selectedStaffId: '',
    selectedVendorId: '',
    hours: ''
  });

  useEffect(() => {
    if (formData.category === '인건비' && formData.selectedStaffId) {
      const staff = staffList.find(s => s.id === formData.selectedStaffId);
      if (staff && staff.type === '알바' && formData.hours) {
        const calculatedAmount = staff.basePay * Number(formData.hours);
        setFormData(prev => ({ ...prev, amount: calculatedAmount.toString() }));
      }
    }
  }, [formData.selectedStaffId, formData.hours, formData.category, staffList]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalDescription = formData.description;
    if (formData.category === '인건비' && formData.selectedStaffId) {
      const staff = staffList.find(s => s.id === formData.selectedStaffId);
      finalDescription = `${staff?.name} ${formData.hours}시간 근무`;
    } else if (formData.category === '식자재' && formData.selectedVendorId) {
      const vendor = vendorList.find(v => v.id === formData.selectedVendorId);
      finalDescription = `${vendor?.name} 매입 - ${formData.description || '정기 납품'}`;
    }

    onSave({
      category: formData.category,
      type: formData.type,
      amount: parseFloat(formData.amount) || 0,
      date: formData.date,
      description: finalDescription,
      staffId: formData.selectedStaffId,
      vendorId: formData.selectedVendorId
    });

    // Reset and close
    setFormData({
      category: '식자재',
      type: '지출',
      amount: '',
      date: new Date().toISOString().split('T')[0],
      description: '',
      selectedStaffId: '',
      selectedVendorId: '',
      hours: ''
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-300">
        <div className="p-6 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-xl font-black text-slate-800 tracking-tight">지출/매출 기록</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-2xl">
            <button
              type="button"
              onClick={() => setFormData({...formData, type: '매출', category: '홀매출'})}
              className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${formData.type === '매출' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
            >
              매출 (+)
            </button>
            <button
              type="button"
              onClick={() => setFormData({...formData, type: '지출', category: '식자재'})}
              className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${formData.type === '지출' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-400'}`}
            >
              지출 (-)
            </button>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">분류 선택</label>
            <div className="grid grid-cols-3 gap-2">
              {(formData.type === '지출' ? CATEGORIES.filter(c => c !== '기타매출') : ['홀매출', '배달매출', '기타매출']).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setFormData({...formData, category: cat})}
                  className={`py-3 rounded-xl text-[10px] font-bold border transition-all ${formData.category === cat ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {/* 인건비 특화 필드 */}
          {formData.category === '인건비' && (
            <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100 space-y-3">
              <label className="block text-[10px] font-black text-orange-400 uppercase">알바 일급 계산기</label>
              <select 
                value={formData.selectedStaffId}
                onChange={e => setFormData({...formData, selectedStaffId: e.target.value})}
                className="w-full px-4 py-2 rounded-xl bg-white border border-orange-200 outline-none text-sm font-bold"
              >
                <option value="">직원 선택</option>
                {staffList.filter(s => s.type === '알바').map(s => (
                  <option key={s.id} value={s.id}>{s.name} (시급: {s.basePay.toLocaleString()}원)</option>
                ))}
              </select>
              <div className="flex gap-2 items-center">
                <input 
                  type="number" 
                  step="0.5"
                  placeholder="시간" 
                  value={formData.hours}
                  onChange={e => setFormData({...formData, hours: e.target.value})}
                  className="w-24 px-4 py-2 rounded-xl bg-white border border-orange-200 outline-none text-sm font-bold"
                />
                <span className="text-xs font-bold text-orange-600">시간 근무</span>
              </div>
            </div>
          )}

          {/* 식자재 특화 필드 (업체 선택) */}
          {formData.category === '식자재' && (
            <div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100 space-y-3">
              <label className="block text-[10px] font-black text-emerald-600 uppercase">공급 업체 선택</label>
              <select 
                value={formData.selectedVendorId}
                onChange={e => setFormData({...formData, selectedVendorId: e.target.value})}
                className="w-full px-4 py-2 rounded-xl bg-white border border-emerald-200 outline-none text-sm font-bold"
              >
                <option value="">거래처를 선택하세요</option>
                {vendorList.map(v => (
                  <option key={v.id} value={v.id}>{v.name}</option>
                ))}
              </select>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1">금액 (원)</label>
              <input
                type="number"
                required
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-black text-slate-800"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1">날짜</label>
              <input
                type="date"
                required
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
          </div>

          <input
            placeholder={formData.category === '인건비' ? "메모 (선택사항)" : "상세 내용 또는 비고"}
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
            value={formData.description}
            onChange={e => setFormData({...formData, description: e.target.value})}
          />

          <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black shadow-xl hover:bg-black transition-all">
            내역 저장하기
          </button>
        </form>
      </div>
    </div>
  );
};

export default EntryModal;

import React, { useState, useMemo, useRef } from 'react';
import { PLEntry, PLSummary, Staff, Vendor } from './types';
import FinancialCard from './components/FinancialCard';
import EntryModal from './components/EntryModal';
import { analyzeFinancials, analyzeReceipt } from './services/geminiService';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3000000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10000 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '서울청과' },
  { id: 'v2', name: '대한유통(고기)' },
  { id: 'v3', name: '팔도농산' },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1200000, date: new Date().toISOString().split('T')[0], description: '평일 점심/저녁' },
  { id: '2', category: '식자재', type: '지출', amount: 450000, date: new Date().toISOString().split('T')[0], description: '서울청과 매입', vendorId: 'v1' },
  { id: '4', category: '관리비', type: '지출', amount: 80000, date: new Date().toISOString().split('T')[0], description: '수도세 분할' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);

  const dailyFixedLaborCost = useMemo(() => {
    return staffList
      .filter(s => s.type === '정규직')
      .reduce((acc, curr) => acc + (curr.basePay / 30), 0);
  }, [staffList]);

  // 인원별 인건비 누적 계산
  const laborBreakdown = useMemo(() => {
    const activeDatesCount = new Set(entries.map(e => e.date)).size || 1;
    return staffList.map(staff => {
      let total = 0;
      if (staff.type === '정규직') {
        total = (staff.basePay / 30) * activeDatesCount;
      } else {
        total = entries
          .filter(e => e.category === '인건비' && e.staffId === staff.id)
          .reduce((acc, curr) => acc + curr.amount, 0);
      }
      return { ...staff, totalAccrued: total };
    }).sort((a, b) => b.totalAccrued - a.totalAccrued);
  }, [staffList, entries]);

  // 업체별 식자재 매입 누적 계산 [추가]
  const vendorBreakdown = useMemo(() => {
    return vendorList.map(vendor => {
      const total = entries
        .filter(e => e.category === '식자재' && e.vendorId === vendor.id)
        .reduce((acc, curr) => acc + curr.amount, 0);
      return { ...vendor, totalSpent: total };
    }).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [vendorList, entries]);

  const stats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const todayRev = todayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayExp = todayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + dailyFixedLaborCost;

    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));
    const monthRev = monthEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const currentDay = new Date().getDate();
    const monthExp = monthEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + (dailyFixedLaborCost * currentDay);

    return { todayProfit: todayRev - todayExp, monthProfit: monthRev - monthExp, monthRev, monthExp };
  }, [entries, dailyFixedLaborCost, todayStr, thisMonthStr]);

  const summary: PLSummary = useMemo(() => {
    const revenue = entries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const manualExpense = entries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const activeDates = new Set(entries.map(e => e.date)).size || 1;
    const autoLaborExpense = dailyFixedLaborCost * activeDates;
    const totalExpense = manualExpense + autoLaborExpense;
    const laborCost = entries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0) + autoLaborExpense;
    const foodCost = entries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);

    return {
      totalRevenue: revenue,
      totalExpense: totalExpense,
      netProfit: revenue - totalExpense,
      foodCostRatio: revenue > 0 ? (foodCost / revenue) * 100 : 0,
      laborCostRatio: revenue > 0 ? (laborCost / revenue) * 100 : 0
    };
  }, [entries, dailyFixedLaborCost]);

  const dailyChartData = useMemo(() => {
    const dates = Array.from(new Set(entries.map(e => e.date))).sort() as string[];
    return dates.slice(-7).map(date => {
      const dayEntries = entries.filter(e => e.date === date);
      return { 
        date: date.slice(5), 
        매출: dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0), 
        지출: dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + dailyFixedLaborCost 
      };
    });
  }, [entries, dailyFixedLaborCost]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    const entryWithId = { ...newEntry, id: `entry-${Date.now()}-${Math.random().toString(36).substr(2, 5)}` };
    setEntries(prev => [...prev, entryWithId]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까? 관련 통계에서 즉시 제외됩니다.')) {
      setEntries(prev => prev.filter(entry => entry.id !== id));
    }
  };

  const handleAddStaff = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newStaff: Staff = {
      id: `staff-${Date.now()}`,
      name: formData.get('name') as string,
      type: formData.get('type') as any,
      basePay: Number(formData.get('basePay'))
    };
    setStaffList(prev => [...prev, newStaff]);
    e.currentTarget.reset();
  };

  const handleAddVendor = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newVendor: Vendor = {
      id: `vendor-${Date.now()}`,
      name: formData.get('name') as string,
    };
    setVendorList(prev => [...prev, newVendor]);
    e.currentTarget.reset();
  };

  return (
    <div className="min-h-screen bg-[#fcfcfd] pb-24">
      <nav className="bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 px-4 py-3">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight">식당 손익 마스터</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsVendorModalOpen(true)} className="bg-white border border-slate-200 text-slate-600 px-3 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-xs flex items-center gap-1.5">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
              업체 관리
            </button>
            <button onClick={() => setIsStaffModalOpen(true)} className="bg-white border border-slate-200 text-slate-600 px-3 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-xs">직원 관리</button>
            <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2 text-sm">기록하기</button>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 pt-8 space-y-8">
        {/* Profit Highlights */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-2xl shadow-indigo-200 relative overflow-hidden group">
            <div className="absolute right-0 top-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
            <div className="relative z-10">
              <h3 className="text-indigo-100 text-xs font-bold uppercase tracking-widest mb-2">오늘 예상 순수익</h3>
              <div className="text-5xl font-black mb-2 tracking-tighter">{stats.todayProfit.toLocaleString()}원</div>
              <div className="flex items-center gap-2 text-indigo-200 text-[10px] font-bold">
                <span className="px-1.5 py-0.5 bg-white/20 rounded">인건비 자동포함</span>
                <span>일일 고정비 {Math.round(dailyFixedLaborCost).toLocaleString()}원 반영</span>
              </div>
            </div>
          </div>
          <div className="bg-white border border-slate-100 p-8 rounded-[2.5rem] shadow-sm flex flex-col justify-between">
            <div>
              <h3 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-2">이번 달 누적 순수익</h3>
              <div className="text-5xl font-black text-slate-800 tracking-tighter">{stats.monthProfit.toLocaleString()}원</div>
            </div>
            <div className="flex gap-6 mt-6 pt-6 border-t border-slate-50">
              <div>
                <span className="text-[10px] text-slate-400 font-bold block uppercase mb-1">매출</span>
                <span className="text-lg font-black text-indigo-600">+{stats.monthRev.toLocaleString()}</span>
              </div>
              <div>
                <span className="text-[10px] text-slate-400 font-bold block uppercase mb-1">지출</span>
                <span className="text-lg font-black text-rose-500">-{stats.monthExp.toLocaleString()}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Breakdown Section Container */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Labor Breakdown */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-slate-800">인원별 인건비</h3>
              <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-lg">LABOR</span>
            </div>
            <div className="space-y-4">
              {laborBreakdown.slice(0, 5).map(staff => (
                <div key={staff.id} className="space-y-1.5">
                  <div className="flex justify-between text-xs font-bold">
                    <span className="text-slate-700">{staff.name}</span>
                    <span className="text-slate-900">{staff.totalAccrued.toLocaleString()}원</span>
                  </div>
                  <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                    <div className="bg-indigo-500 h-full" style={{ width: `${Math.min(100, (staff.totalAccrued / (summary.totalRevenue || 1)) * 100 * 5)}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Vendor Breakdown [추가된 업체별 섹션] */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-slate-800">업체별 식자재비</h3>
              <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded-lg">SUPPLY</span>
            </div>
            <div className="space-y-4">
              {vendorBreakdown.slice(0, 5).map(vendor => (
                <div key={vendor.id} className="space-y-1.5">
                  <div className="flex justify-between text-xs font-bold">
                    <span className="text-slate-700">{vendor.name}</span>
                    <span className="text-slate-900">{vendor.totalSpent.toLocaleString()}원</span>
                  </div>
                  <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                    <div className="bg-emerald-500 h-full" style={{ width: `${Math.min(100, (vendor.totalSpent / (summary.totalRevenue || 1)) * 100 * 5)}%` }}></div>
                  </div>
                </div>
              ))}
              {vendorBreakdown.length === 0 && <p className="text-xs text-slate-400 py-4 text-center">등록된 매입 내역이 없습니다.</p>}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h3 className="font-black text-slate-800 mb-6 flex items-center gap-2">
                <div className="w-1.5 h-6 bg-indigo-600 rounded-full"></div>
                최근 7일 수익 차트
              </h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={dailyChartData}>
                    <defs>
                      <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="매출" stroke="#6366f1" fill="url(#colorRev)" strokeWidth={4} />
                    <Area type="monotone" dataKey="지출" stroke="#f43f5e" fillOpacity={0} strokeWidth={4} strokeDasharray="8 8" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Records Table */}
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                <h3 className="font-black text-slate-800">전체 기록 내역</h3>
                <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-bold uppercase">{entries.length} Items</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-50">
                    <tr>
                      <th className="px-8 py-5">날짜</th>
                      <th className="px-8 py-5">분류</th>
                      <th className="px-8 py-5">내용</th>
                      <th className="px-8 py-5 text-right">금액</th>
                      <th className="px-8 py-5 text-center">삭제</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                      <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="px-8 py-5 text-xs font-bold text-slate-400">{entry.date.slice(5)}</td>
                        <td className="px-8 py-5">
                          <span className={`px-2.5 py-1 rounded-xl text-[10px] font-black uppercase ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                            {entry.category}
                          </span>
                        </td>
                        <td className="px-8 py-5 text-sm font-bold text-slate-700">
                          {entry.description}
                        </td>
                        <td className={`px-8 py-5 text-right font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                          {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                        </td>
                        <td className="px-8 py-5 text-center">
                          <button 
                            onClick={(e) => {
                              e.stopPropagation();
                              handleDeleteEntry(entry.id);
                            }}
                            className="p-2.5 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-2xl transition-all"
                          >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 text-white p-8 rounded-[2.5rem] shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-black text-lg">마스터 관리</h3>
              </div>
              <div className="space-y-3">
                <button onClick={() => setIsStaffModalOpen(true)} className="w-full flex items-center justify-between bg-white/5 p-4 rounded-3xl border border-white/5 hover:bg-white/10 transition-all">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-xl bg-indigo-500/20 flex items-center justify-center text-indigo-400">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
                    </div>
                    <span className="font-bold text-sm">직원 관리 ({staffList.length})</span>
                  </div>
                  <svg className="w-4 h-4 text-white/30" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                </button>
                <button onClick={() => setIsVendorModalOpen(true)} className="w-full flex items-center justify-between bg-white/5 p-4 rounded-3xl border border-white/5 hover:bg-white/10 transition-all">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-xl bg-emerald-500/20 flex items-center justify-center text-emerald-400">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
                    </div>
                    <span className="font-bold text-sm">업체 관리 ({vendorList.length})</span>
                  </div>
                  <svg className="w-4 h-4 text-white/30" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Staff Modal */}
      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg overflow-hidden p-10 animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">직원 구성 설정</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-full hover:bg-slate-200 transition-all text-slate-500">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddStaff} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="직원 성명" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none text-sm font-bold border-2 border-transparent focus:border-indigo-500 transition-all" />
                <select name="type" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none text-sm font-black border-2 border-transparent focus:border-indigo-500 appearance-none transition-all">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="basePay" type="number" required placeholder="급여(월급/시급)" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none text-lg font-black border-2 border-transparent focus:border-indigo-500 transition-all" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-black transition-all">등록 완료</button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto">
              {staffList.map(s => (
                <div key={s.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-sm">{s.name} ({s.type})</span>
                  <button onClick={() => setStaffList(l => l.filter(i => i.id !== s.id))} className="text-rose-500 text-xs font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Vendor Modal [추가] */}
      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg overflow-hidden p-10 animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">식자재 업체 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-full hover:bg-slate-200 transition-all text-slate-500">
