      const dayEntries = entries.filter(e => e.date === date);
      return { 
        date: date.slice(5), 
        매출: dayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0), 
        지출: dayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0) + dailyFixedLaborCost 
      };
    });
