            <div className="w-10 h-10 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight">식당 손익 마스터</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white border border-slate-200 text-slate-600 px-3 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-xs flex items-center gap-1.5">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
              고정지출 관리
            </button>
            <button onClick={() => setIsVendorModalOpen(true)} className="bg-white border border-slate-200 text-slate-600 px-3 py-2.5 rounded-2xl font-bold hover:bg-slate-50 transition-all text-xs">업체 관리</button>
