                  <div className="w-full bg-slate-100 h-1 rounded-full overflow-hidden">
                    <div className="bg-indigo-500 h-full" style={{ width: `${Math.min(100, (staff.totalAccrued / (summary.totalRevenue || 1)) * 100 * 2)}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Vendor Breakdown */}
          <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm p-6">
            <h3 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2">
              <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
              업체별 식자재비
            </h3>
            <div className="space-y-4">
              {vendorBreakdown.map(vendor => (
                <div key={vendor.id} className="space-y-1">
                  <div className="flex justify-between text-[11px] font-bold">
                    <span>{vendor.name}</span>
                    <span>{vendor.totalSpent.toLocaleString()}원</span>
                  </div>
                  <div className="w-full bg-slate-100 h-1 rounded-full overflow-hidden">
                    <div className="bg-emerald-500 h-full" style={{ width: `${Math.min(100, (vendor.totalSpent / (summary.totalRevenue || 1)) * 100 * 2)}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Fixed Expense Breakdown [추가] */}
          <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm p-6">
            <h3 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2">
              <svg className="w-4 h-4 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
              항목별 고정지출
            </h3>
            <div className="space-y-4">
              {fixedExpenseBreakdown.map(item => (
                <div key={item.id} className="space-y-1">
                  <div className="flex justify-between text-[11px] font-bold">
                    <span>{item.name}</span>
                    <span>{item.totalSpent.toLocaleString()}원</span>
                  </div>
                  <div className="w-full bg-slate-100 h-1 rounded-full overflow-hidden">
                    <div className="bg-blue-500 h-full" style={{ width: `${Math.min(100, (item.totalSpent / (summary.totalRevenue || 1)) * 100 * 2)}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            {/* Chart & Table components from current version... */}
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                <h3 className="font-black text-slate-800">최근 지출/매출 내역</h3>
                <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-bold uppercase">{entries.length} Items</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-50">
                    <tr>
                      <th className="px-8 py-5">날짜</th>
                      <th className="px-8 py-5">분류</th>
                      <th className="px-8 py-5">내용</th>
                      <th className="px-8 py-5 text-right">금액</th>
                      <th className="px-8 py-5 text-center">삭제</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                      <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="px-8 py-5 text-xs font-bold text-slate-400">{entry.date.slice(5)}</td>
                        <td className="px-8 py-5">
                          <span className={`px-2.5 py-1 rounded-xl text-[10px] font-black uppercase ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                            {entry.category}
                          </span>
                        </td>
                        <td className="px-8 py-5 text-sm font-bold text-slate-700">{entry.description}</td>
                        <td className={`px-8 py-5 text-right font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                          {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                        </td>
                        <td className="px-8 py-5 text-center">
                          <button onClick={() => handleDeleteEntry(entry.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-all">
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Management Modals */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900">고정지출 항목 관리</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-2 rounded-full">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddFixedExpense} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-3">
                <input name="name" required placeholder="항목명 (예: 수도요금)" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="category" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">비고정지출</option>
                </select>
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black hover:bg-blue-700 transition-all">신규 항목 등록</button>
            </form>
            <div className="space-y-2 max-h-48 overflow-y-auto">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl group">
                  <span className="font-bold text-sm">{item.name} <span className="text-[10px] text-slate-400 ml-2">({item.defaultCategory})</span></span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 opacity-0 group-hover:opacity-100 text-xs font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Other Modals (Staff, Vendor) remained similar but integrated... */}
      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900">직원 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-full">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddStaff} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-3">
                <input name="name" required placeholder="이름" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="type" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="basePay" type="number" required placeholder="급여(월급/시급)" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black">등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900">식자재 업체 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-full">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddVendor} className="space-y-4 mb-8">
              <input name="name" required placeholder="업체명" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black">등록</button>
            </form>
          </div>
        </div>
      )}

      <EntryModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleAddEntry} 
        staffList={staffList}
        vendorList={vendorList}
        fixedExpenseItems={fixedExpenseItems}
      />
    </div>
  );
};

export default App;

export type EntryType = '매출' | '지출';

export type CategoryType = '식자재' | '인건비' | '월세' | '관리비' | '비고정지출' | '판매수수료' | '기타매출';

export type StaffType = '정규직' | '알바';

export interface Staff {
  id: string;
  name: string;
  type: StaffType;
  basePay: number; // 월급 또는 시급
}

export interface Vendor {
  id: string;
  name: string;
  contact?: string;
}

export interface FixedExpenseItem {
  id: string;
  name: string;
  defaultCategory: '월세' | '관리비' | '비고정지출';
  monthlyAmount: number; // 월 고정 금액 추가
}

export interface PLEntry {
  id: string;
  category: string;
  type: EntryType;
  amount: number;
  date: string;
  description: string;
  staffId?: string;
  vendorId?: string;
  fixedExpenseId?: string;
}

export interface PLSummary {
  totalRevenue: number;
  totalExpense: number;
  netProfit: number;
  foodCostRatio: number;
  laborCostRatio: number;
}

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3000000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10000 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '서울청과' },
  { id: 'v2', name: '대한유통(고기)' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 임대료', defaultCategory: '월세', monthlyAmount: 2500000 },
  { id: 'f2', name: '기본 관리비', defaultCategory: '관리비', monthlyAmount: 300000 },
  { id: 'f3', name: '인터넷/정수기', defaultCategory: '비고정지출', monthlyAmount: 100000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1200000, date: new Date().toISOString().split('T')[0], description: '평일 점심/저녁' },
  { id: '2', category: '식자재', type: '지출', amount: 450000, date: new Date().toISOString().split('T')[0], description: '서울청과 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  // 일일 고정비 계산 (정규직 급여 + 고정지출 항목)
  const dailyFixedOverhead = useMemo(() => {
    const monthlyLabor = staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0);
    const monthlyFixed = fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0);
    return (monthlyLabor + monthlyFixed) / 30;
  }, [staffList, fixedExpenseItems]);

  // 통합 통계 계산 (6분할 대시보드용)
  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const todayActualRev = todayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayActualExp = todayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayTotalExp = todayActualExp + dailyFixedOverhead;

    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));
    const monthActualRev = monthEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const monthActualExp = monthEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const monthTotalOverhead = dailyFixedOverhead * currentDayOfMonth;
    const monthTotalExp = monthActualExp + monthTotalOverhead;

    return {
      today: { rev: todayActualRev, exp: todayTotalExp, profit: todayActualRev - todayTotalExp },
      month: { rev: monthActualRev, exp: monthTotalExp, profit: monthActualRev - monthTotalExp }
    };
  }, [entries, dailyFixedOverhead, todayStr, thisMonthStr, currentDayOfMonth]);

  // Breakdown Logic
  const laborBreakdown = useMemo(() => {
    return staffList.map(staff => {
      let total = 0;
      if (staff.type === '정규직') {
        total = (staff.basePay / 30) * currentDayOfMonth;
      } else {
        total = entries
          .filter(e => e.category === '인건비' && e.staffId === staff.id && e.date.startsWith(thisMonthStr))
          .reduce((acc, curr) => acc + curr.amount, 0);
      }
      return { ...staff, totalAccrued: total };
    }).sort((a, b) => b.totalAccrued - a.totalAccrued);
  }, [staffList, entries, thisMonthStr, currentDayOfMonth]);

  const vendorBreakdown = useMemo(() => {
    return vendorList.map(vendor => {
      const total = entries
        .filter(e => e.category === '식자재' && e.vendorId === vendor.id && e.date.startsWith(thisMonthStr))
        .reduce((acc, curr) => acc + curr.amount, 0);
      return { ...vendor, totalSpent: total };
    }).sort((a, b) => b.totalSpent - a.totalSpent);
  }, [vendorList, entries, thisMonthStr]);

  const fixedBreakdown = useMemo(() => {
    return fixedExpenseItems.map(item => {
      // 안분된 고정비 + 실제 추가 납부한 금액 합산
      const amortized = (item.monthlyAmount / 30) * currentDayOfMonth;
      const actualExtra = entries
        .filter(e => e.fixedExpenseId === item.id && e.date.startsWith(thisMonthStr))
        .reduce((acc, curr) => acc + curr.amount, 0);
      return { ...item, total: amortized + actualExtra };
    }).sort((a, b) => b.total - a.total);
  }, [fixedExpenseItems, entries, thisMonthStr, currentDayOfMonth]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...newEntry, id: `entry-${Date.now()}` }]);
  };

  const handleAddFixedExpense = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    setFixedExpenseItems(prev => [...prev, { 
      id: `fixed-${Date.now()}`, 
      name: formData.get('name') as string,
      defaultCategory: formData.get('category') as any,
      monthlyAmount: Number(formData.get('amount'))
    }]);
    e.currentTarget.reset();
  };

  const SummaryCard = ({ title, value, color, subtitle }: { title: string, value: number, color: string, subtitle: string }) => (
    <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col justify-between h-full hover:shadow-md transition-shadow">
      <div>
        <h4 className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">{title}</h4>
        <div className={`text-2xl font-black tracking-tighter ${color}`}>
          {value.toLocaleString()}원
        </div>
      </div>
      <p className="text-[10px] font-bold text-slate-300 mt-2">{subtitle}</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#fcfcfd] pb-24 text-slate-900 font-sans">
      <nav className="bg-white/90 backdrop-blur-xl border-b border-slate-100 sticky top-0 z-40 px-4 py-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <h1 className="text-xl font-black text-slate-900 tracking-tighter">P&L DASHBOARD</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-6 py-2.5 rounded-2xl font-black shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all text-sm">기록하기</button>
          </div>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-4 pt-10 space-y-12">
        {/* Dashboard 6-Grid */}
        <section className="space-y-6">
          <div>
            <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest ml-1 mb-4 flex items-center gap-2">
              <span className="w-4 h-1 bg-indigo-500 rounded-full"></span> TODAY'S PERFORMANCE
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <SummaryCard title="오늘 매출" value={dashboardStats.today.rev} color="text-indigo-600" subtitle="현장/배달 실시간 합계" />
              <SummaryCard title="오늘 지출" value={dashboardStats.today.exp} color="text-rose-500" subtitle={`고정비 ${Math.round(dailyFixedOverhead).toLocaleString()}원 포함`} />
              <div className="bg-emerald-600 p-6 rounded-[2rem] text-white shadow-xl shadow-emerald-50 hover:scale-[1.02] transition-transform">
                <h4 className="text-emerald-100 text-[10px] font-black uppercase tracking-widest mb-1">오늘 예상 순수익</h4>
                <div className="text-3xl font-black tracking-tighter">
                  {dashboardStats.today.profit.toLocaleString()}원
                </div>
                <p className="text-[10px] font-bold text-emerald-200 mt-2">일일 고정비 자동 차감 완료</p>
              </div>
            </div>
          </div>

          <div className="pt-4">
            <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest ml-1 mb-4 flex items-center gap-2">
              <span className="w-4 h-1 bg-emerald-500 rounded-full"></span> MONTH-TO-DATE (MTD)
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <SummaryCard title="이번 달 매출" value={dashboardStats.month.rev} color="text-slate-800" subtitle={`${currentDayOfMonth}일간 누적 실적`} />
              <SummaryCard title="이번 달 지출" value={dashboardStats.month.exp} color="text-slate-800" subtitle={`고정비/인건비 안분액 포함`} />
              <SummaryCard title="이번 달 순수익" value={dashboardStats.month.profit} color="text-emerald-600 font-black border-emerald-100 border-2" subtitle="영업 비용 완전 차감" />
            </div>
          </div>
        </section>

        {/* Breakdown Analytics */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Labor */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm p-8">
