          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-slate-900 rounded-[1.2rem] flex items-center justify-center text-white shadow-2xl shadow-slate-200 rotate-6">
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tighter text-slate-900 leading-none">BIZ ANALYST</h1>
              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1 block">Financial Master v2.5</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-5 py-3 rounded-2xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              고정비 설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-8 py-3 rounded-2xl bg-indigo-600 text-white text-xs font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95">
              기록하기
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-12 space-y-16">
        {/* Today's Section */}
        <section className="space-y-8">
          <div className="flex items-end justify-between px-2">
            <div>
              <h2 className="text-4xl font-black tracking-tighter text-slate-900">오늘의 경영 실적</h2>
              <p className="text-slate-400 text-sm font-medium mt-2">일일 고정비 <span className="text-rose-500 font-bold">{Math.round(dailyFixedOverhead).toLocaleString()}원</span>이 자동 차감된 결과입니다.</p>
            </div>
            <div className="hidden md:block text-right">
              <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Update Time</span>
              <p className="text-sm font-bold text-slate-600">{new Date().toLocaleTimeString()}</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="Today Revenue" value={dashboardStats.today.rev} type="rev" />
            <MetricCard title="Today Expense" value={dashboardStats.today.exp} type="exp" />
            <MetricCard title="Today Net Profit" value={dashboardStats.today.profit} type="profit" isMain />
          </div>
        </section>

        {/* MTD Section */}
        <section className="space-y-8 pt-4">
          <div className="flex items-end justify-between px-2 border-l-4 border-emerald-500 pl-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">{new Date().getMonth() + 1}월 누적 리포트</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">{currentDayOfMonth}일 동안의 영업 성과를 집계했습니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="MTD Revenue" value={dashboardStats.month.rev} type="rev" />
            <MetricCard title="MTD Expense" value={dashboardStats.month.exp} type="exp" />
            <MetricCard title="MTD Net Profit" value={dashboardStats.month.profit} type="profit" />
          </div>
        </section>

        {/* Management Board */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-8">
          {/* Quick Actions & Settings */}
