             </div>
          </div>

          {/* 최근 거래 내역 테이블 */}
          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-10 py-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest">{entries.length}건의 내역</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[500px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-10 py-6">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-1 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-10 py-6">
                        <span className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className={`px-10 py-6 text-right font-black text-md ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                        {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </main>

      {/* 모달창 스타일링 (한글화) */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">고정지출 마스터</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddFixedExpense} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">항목명</label>
                  <input name="name" required placeholder="수도광열비" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">분류</label>
                  <select name="category" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all">
                    <option value="월세">월세</option>
                    <option value="관리비">관리비</option>
                    <option value="비고정지출">비고정지출</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">월 평균 총 금액</label>
                <input name="amount" type="number" required placeholder="0" className="w-full px-8 py-5 bg-slate-50 rounded-[2rem] outline-none font-black text-2xl focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-black transition-all shadow-2xl shadow-slate-200">
                새 항목 시스템 등록
              </button>
            </form>
            <div className="space-y-3 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-5 bg-slate-50 rounded-2xl group border border-transparent hover:border-slate-100 transition-all">
                  <div>
                    <span className="font-black text-sm text-slate-800">{item.name}</span>
                    <span className="text-[10px] text-slate-400 block font-bold uppercase tracking-tighter">월간: {item.monthlyAmount.toLocaleString()}원</span>
                  </div>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 opacity-0 group-hover:opacity-100 text-[10px] font-black hover:text-rose-600 transition-all">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">인사 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="type" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="급여(월급/시급)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black">신규 직원 등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">공급처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <input name="name" required placeholder="업체명 (예: 신세계푸드)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-100">협력사 등록</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { EntryType, PLEntry, CategoryType, Staff, Vendor, FixedExpenseItem } from '../types';

interface EntryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: Omit<PLEntry, 'id'>) => void;
  staffList: Staff[];
  vendorList: Vendor[];
  fixedExpenseItems: FixedExpenseItem[];
}

const CATEGORIES: CategoryType[] = ['식자재', '인건비', '월세', '관리비', '비고정지출', '판매수수료', '기타매출'];

const EntryModal: React.FC<EntryModalProps> = ({ isOpen, onClose, onSave, staffList, vendorList, fixedExpenseItems }) => {
  const [formData, setFormData] = useState({
    category: '식자재',
    type: '지출' as EntryType,
    amount: '',
    date: new Date().toISOString().split('T')[0],
    description: '',
    selectedStaffId: '',
    selectedVendorId: '',
    selectedFixedExpenseId: '',
    hours: ''
  });

  useEffect(() => {
    if (formData.category === '인건비' && formData.selectedStaffId) {
      const staff = staffList.find(s => s.id === formData.selectedStaffId);
      if (staff && staff.type === '알바' && formData.hours) {
        const calculatedAmount = staff.basePay * Number(formData.hours);
        setFormData(prev => ({ ...prev, amount: calculatedAmount.toString() }));
      }
    }
  }, [formData.selectedStaffId, formData.hours, formData.category, staffList]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalDescription = formData.description;
    if (formData.category === '인건비' && formData.selectedStaffId) {
      const staff = staffList.find(s => s.id === formData.selectedStaffId);
      finalDescription = `${staff?.name} ${formData.hours}시간 근무`;
    } else if (formData.category === '식자재' && formData.selectedVendorId) {
      const vendor = vendorList.find(v => v.id === formData.selectedVendorId);
      finalDescription = `${vendor?.name} 매입 - ${formData.description || '정기 납품'}`;
    } else if (['월세', '관리비', '비고정지출'].includes(formData.category) && formData.selectedFixedExpenseId) {
      const item = fixedExpenseItems.find(i => i.id === formData.selectedFixedExpenseId);
      finalDescription = `${item?.name} 납부 - ${formData.description || '정기 지출'}`;
    }

    onSave({
      category: formData.category,
      type: formData.type,
      amount: parseFloat(formData.amount) || 0,
      date: formData.date,
      description: finalDescription,
      staffId: formData.selectedStaffId,
      vendorId: formData.selectedVendorId,
      fixedExpenseId: formData.selectedFixedExpenseId
    });

    setFormData({
      category: '식자재',
      type: '지출',
      amount: '',
      date: new Date().toISOString().split('T')[0],
      description: '',
      selectedStaffId: '',
      selectedVendorId: '',
      selectedFixedExpenseId: '',
      hours: ''
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-300">
        <div className="p-6 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-xl font-black text-slate-800 tracking-tight">지출/매출 상세 기록</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-2xl">
            <button
              type="button"
              onClick={() => setFormData({...formData, type: '매출', category: '홀매출'})}
              className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${formData.type === '매출' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
            >
              매출 추가 (+)
            </button>
            <button
              type="button"
              onClick={() => setFormData({...formData, type: '지출', category: '식자재'})}
              className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${formData.type === '지출' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-400'}`}
            >
              지출 기록 (-)
            </button>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">분류 선택</label>
            <div className="grid grid-cols-3 gap-2">
              {(formData.type === '지출' ? CATEGORIES.filter(c => c !== '기타매출') : ['홀매출', '배달매출', '기타매출']).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setFormData({...formData, category: cat})}
                  className={`py-3 rounded-xl text-[10px] font-bold border transition-all ${formData.category === cat ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {formData.category === '인건비' && (
            <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100 space-y-3">
              <label className="block text-[10px] font-black text-orange-400 uppercase">알바 일급 계산기</label>
              <select 
                value={formData.selectedStaffId}
                onChange={e => setFormData({...formData, selectedStaffId: e.target.value})}
                className="w-full px-4 py-2 rounded-xl bg-white border border-orange-200 outline-none text-sm font-bold"
              >
                <option value="">대상 직원 선택</option>
                {staffList.filter(s => s.type === '알바').map(s => (
                  <option key={s.id} value={s.id}>{s.name} (시급: {s.basePay.toLocaleString()}원)</option>
                ))}
              </select>
              <div className="flex gap-2 items-center">
                <input 
                  type="number" 
                  step="0.5"
                  placeholder="시간" 
                  value={formData.hours}
                  onChange={e => setFormData({...formData, hours: e.target.value})}
                  className="w-24 px-4 py-2 rounded-xl bg-white border border-orange-200 outline-none text-sm font-bold"
                />
                <span className="text-xs font-bold text-orange-600">시간 근무 적용</span>
              </div>
            </div>
          )}

          {formData.category === '식자재' && (
            <div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100 space-y-3">
              <label className="block text-[10px] font-black text-emerald-600 uppercase">매입처 선택</label>
              <select 
                value={formData.selectedVendorId}
                onChange={e => setFormData({...formData, selectedVendorId: e.target.value})}
                className="w-full px-4 py-2 rounded-xl bg-white border border-emerald-200 outline-none text-sm font-bold"
              >
                <option value="">거래처를 선택하세요</option>
                {vendorList.map(v => (
                  <option key={v.id} value={v.id}>{v.name}</option>
                ))}
              </select>
            </div>
          )}

          {['월세', '관리비', '비고정지출'].includes(formData.category) && (
            <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 space-y-3">
              <label className="block text-[10px] font-black text-blue-600 uppercase">고정 지출 매칭</label>
              <select 
                value={formData.selectedFixedExpenseId}
                onChange={e => setFormData({...formData, selectedFixedExpenseId: e.target.value})}
                className="w-full px-4 py-2 rounded-xl bg-white border border-blue-200 outline-none text-sm font-bold"
              >
                <option value="">등록된 고정 항목 선택</option>
                {fixedExpenseItems.map(item => (
                  <option key={item.id} value={item.id}>{item.name}</option>
                ))}
              </select>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1">금액 (원)</label>
              <input
                type="number"
                required
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-black text-slate-800"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1">발생 날짜</label>
              <input
                type="date"
                required
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
          </div>

          <input
            placeholder="상세 내역 (예: 야채 청과물 매입)"
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
            value={formData.description}
            onChange={e => setFormData({...formData, description: e.target.value})}
          />

          <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black shadow-xl hover:bg-black transition-all">
            데이터 저장하기
          </button>
        </form>
      </div>
    </div>
  );
};

export default EntryModal;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  // 매일 자동으로 나가는 총 비용 (정규직 월급/30 + 고정지출/30)
  const dailyFixedOverhead = useMemo(() => {
    const monthlyLabor = staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0);
    const monthlyFixed = fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0);
    return (monthlyLabor + monthlyFixed) / 30;
  }, [staffList, fixedExpenseItems]);

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const todayActualRev = todayEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayActualExp = todayEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const todayTotalExp = todayActualExp + dailyFixedOverhead;

    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));
    const monthActualRev = monthEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const monthActualExp = monthEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const monthTotalOverhead = dailyFixedOverhead * currentDayOfMonth;
    const monthTotalExp = monthActualExp + monthTotalOverhead;

    return {
      today: { rev: todayActualRev, exp: todayTotalExp, profit: todayActualRev - todayTotalExp },
      month: { rev: monthActualRev, exp: monthTotalExp, profit: monthActualRev - monthTotalExp }
    };
  }, [entries, dailyFixedOverhead, todayStr, thisMonthStr, currentDayOfMonth]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...newEntry, id: `entry-${Date.now()}` }]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleAddFixedExpense = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    setFixedExpenseItems(prev => [...prev, { 
      id: `fixed-${Date.now()}`, 
      name: formData.get('name') as string,
      defaultCategory: formData.get('category') as any,
      monthlyAmount: Number(formData.get('amount'))
    }]);
    (e.target as HTMLFormElement).reset();
  };

  const MetricCard = ({ title, value, type, isMain }: { title: string, value: number, type: 'rev' | 'exp' | 'profit', isMain?: boolean }) => {
    const configs = {
      rev: { bg: 'bg-white', text: 'text-indigo-600', label: '총 매출액' },
      exp: { bg: 'bg-white', text: 'text-rose-500', label: '총 지출액' },
      profit: { bg: isMain ? 'bg-slate-900' : 'bg-emerald-500', text: 'text-white', label: '실제 순이익' }
    };
    const config = configs[type];

    return (
      <div className={`${config.bg} p-8 rounded-[2.5rem] border border-slate-100 shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 flex flex-col justify-between min-h-[160px]`}>
        <div>
          <span className="text-[11px] font-black uppercase tracking-widest opacity-50 mb-1 block">{title}</span>
          <h4 className={`text-3xl font-black tracking-tighter ${config.text}`}>
            {value.toLocaleString()}<span className="text-sm ml-1 font-bold">원</span>
          </h4>
        </div>
        <div className="flex items-center gap-2 mt-4">
           <div className={`w-1.5 h-1.5 rounded-full ${config.text.replace('text-', 'bg-')}`}></div>
           <span className="text-[10px] font-bold text-slate-400">{config.label} 기준</span>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-20">
      {/* 프리미엄 내비게이션 */}
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-slate-900 rounded-[1.2rem] flex items-center justify-center text-white shadow-2xl shadow-slate-200 rotate-6">
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tighter text-slate-900 leading-none">스마트 손익 분석</h1>
              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1 block">프리미엄 경영 마스터 v2.5</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-5 py-3 rounded-2xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              고정비 설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-8 py-3 rounded-2xl bg-indigo-600 text-white text-xs font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95">
              기록하기
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-12 space-y-16">
        {/* 오늘 섹션 */}
        <section className="space-y-8">
          <div className="flex items-end justify-between px-2">
            <div>
              <h2 className="text-4xl font-black tracking-tighter text-slate-900">오늘의 경영 실적</h2>
              <p className="text-slate-400 text-sm font-medium mt-2">일일 고정 운영비 <span className="text-rose-500 font-bold">{Math.round(dailyFixedOverhead).toLocaleString()}원</span>이 자동 차감되었습니다.</p>
            </div>
            <div className="hidden md:block text-right">
              <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">업데이트 시간</span>
              <p className="text-sm font-bold text-slate-600">{new Date().toLocaleTimeString('ko-KR')}</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="오늘의 매출" value={dashboardStats.today.rev} type="rev" />
            <MetricCard title="오늘의 지출" value={dashboardStats.today.exp} type="exp" />
            <MetricCard title="오늘의 순이익" value={dashboardStats.today.profit} type="profit" isMain />
          </div>
        </section>

        {/* 이번 달 누적 섹션 */}
        <section className="space-y-8 pt-4">
          <div className="flex items-end justify-between px-2 border-l-4 border-emerald-500 pl-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">{new Date().getMonth() + 1}월 통합 누적 성과</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">최근 {currentDayOfMonth}일 동안의 영업 실적을 분석했습니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="이번 달 총 매출" value={dashboardStats.month.rev} type="rev" />
            <MetricCard title="이번 달 총 지출" value={dashboardStats.month.exp} type="exp" />
            <MetricCard title="이번 달 총 순이익" value={dashboardStats.month.profit} type="profit" />
          </div>
        </section>

        {/* 경영 관리 보드 */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-8">
          {/* 퀵 액션 및 설정 */}
          <div className="bg-slate-900 rounded-[3rem] p-12 text-white shadow-2xl shadow-slate-300 relative overflow-hidden">
             <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/20 blur-[100px] rounded-full -mr-20 -mt-20"></div>
             <div className="relative z-10 space-y-8">
                <div className="space-y-3">
                  <h3 className="text-3xl font-black tracking-tight">마스터 관리자</h3>
                  <p className="text-slate-400 text-sm leading-relaxed max-w-sm">직원, 거래처, 고정 지출 항목을 상세히 설정하여 더 정확한 손익 분석 보고서를 확인하세요.</p>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setIsStaffModalOpen(true)} className="p-6 rounded-[2rem] bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                    <div className="w-10 h-10 rounded-xl bg-indigo-500/20 flex items-center justify-center text-indigo-400 mb-4">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                    </div>
                    <span className="font-black text-sm block">직원 관리</span>
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">인건비 자동 계산</span>
                  </button>
                  <button onClick={() => setIsVendorModalOpen(true)} className="p-6 rounded-[2rem] bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                    <div className="w-10 h-10 rounded-xl bg-emerald-500/20 flex items-center justify-center text-emerald-400 mb-4">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
                    </div>
                    <span className="font-black text-sm block">거래처 관리</span>
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">공급망 현황 파악</span>
                  </button>
                </div>
                <div className="p-8 rounded-[2rem] bg-indigo-600 shadow-2xl shadow-indigo-900/40">
                  <div className="flex justify-between items-center">
                    <div>
                      <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">현재 일일 고정 운영비</span>
                      <h4 className="text-3xl font-black mt-1">-{Math.round(dailyFixedOverhead).toLocaleString()}원</h4>
                    </div>
                    <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white/10 p-3 rounded-xl hover:bg-white/20 transition-all">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    </button>
                  </div>
                </div>
             </div>
          </div>

          {/* 최근 거래 내역 테이블 */}
          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-10 py-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest">{entries.length}건의 내역</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[500px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-10 py-6">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-1 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-10 py-6">
                        <span className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-10 py-6 text-right">
                        <div className="flex items-center justify-end gap-4">
                          <span className={`font-black text-md ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)}
                            className="opacity-0 group-hover:opacity-100 p-2 text-rose-400 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50"
                            title="삭제"
                          >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </main>

      {/* 모달창 스타일링 (한글화) */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">고정지출 마스터</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddFixedExpense} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">항목명</label>
                  <input name="name" required placeholder="수도광열비" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">분류</label>
                  <select name="category" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all">
                    <option value="월세">월세</option>
                    <option value="관리비">관리비</option>
                    <option value="비고정지출">비고정지출</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">월 평균 총 금액</label>
                <input name="amount" type="number" required placeholder="0" className="w-full px-8 py-5 bg-slate-50 rounded-[2rem] outline-none font-black text-2xl focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-black transition-all shadow-2xl shadow-slate-200">
                새 항목 시스템 등록
              </button>
            </form>
            <div className="space-y-3 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-5 bg-slate-50 rounded-2xl group border border-transparent hover:border-slate-100 transition-all">
                  <div>
                    <span className="font-black text-sm text-slate-800">{item.name}</span>
                    <span className="text-[10px] text-slate-400 block font-bold uppercase tracking-tighter">월간: {item.monthlyAmount.toLocaleString()}원</span>
                  </div>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 opacity-0 group-hover:opacity-100 text-[10px] font-black hover:text-rose-600 transition-all">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">인사 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="type" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="급여(월급/시급)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black">신규 직원 등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
