                <input name="amount" type="number" required placeholder="0" className="w-full px-8 py-5 bg-slate-50 rounded-[2rem] outline-none font-black text-2xl focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-black transition-all shadow-2xl shadow-slate-200">
                새 항목 시스템 등록
              </button>
            </form>
            <div className="space-y-3 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-5 bg-slate-50 rounded-2xl group border border-transparent hover:border-slate-100 transition-all">
                  <div>
                    <span className="font-black text-sm text-slate-800">{item.name}</span>
                    <span className="text-[10px] text-slate-400 block font-bold uppercase tracking-tighter">월간: {item.monthlyAmount.toLocaleString()}원</span>
                  </div>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 opacity-0 group-hover:opacity-100 text-[10px] font-black hover:text-rose-600 transition-all">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">인사 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="type" className="px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="급여(월급/시급)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black">신규 직원 등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">공급처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <input name="name" required placeholder="업체명 (예: 신세계푸드)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-100">협력사 등록</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  // 월간 고정비 및 정규직 인건비 총합
  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const dailyFixedOverhead = useMemo(() => {
    return (monthlyLaborFixed + monthlyFixedCostOnly) / 30;
  }, [monthlyLaborFixed, monthlyFixedCostOnly]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);

    // 고정 지출 (일별/월별 안분)
    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    // 개별 항목별 지출
    const foodCost = filteredEntries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = filteredEntries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = filteredEntries.filter(e => 
      e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category)
    ).reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev,
      exp: totalExp,
      profit: rev - totalExp,
      foodCost,
      laborCost: totalLabor,
      fixedCost: fixedExpensePart,
      variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (fixedExpensePart / rev) * 100 : 0,
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));

    return {
      today: calculateStats(todayEntries, 1),
      month: calculateStats(monthEntries, currentDayOfMonth)
    };
  }, [entries, dailyFixedOverhead, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...newEntry, id: `entry-${Date.now()}` }]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleAddFixedExpense = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    setFixedExpenseItems(prev => [...prev, { 
      id: `fixed-${Date.now()}`, 
      name: formData.get('name') as string,
      defaultCategory: formData.get('category') as any,
      monthlyAmount: Number(formData.get('amount'))
    }]);
    (e.target as HTMLFormElement).reset();
  };

  const MetricCard = ({ title, value, type, isMain, suffix = "원" }: { title: string, value: number | string, type: 'rev' | 'exp' | 'profit' | 'ratio', isMain?: boolean, suffix?: string }) => {
    const configs = {
      rev: { bg: 'bg-white', text: 'text-indigo-600', label: '수익' },
      exp: { bg: 'bg-white', text: 'text-rose-500', label: '지출' },
      profit: { bg: isMain ? 'bg-slate-900' : 'bg-emerald-500', text: 'text-white', label: '결과' },
      ratio: { bg: 'bg-slate-50', text: 'text-slate-900', label: '비율' }
    };
    const config = configs[type];
    const displayValue = typeof value === 'number' ? (type === 'ratio' ? value.toFixed(1) : value.toLocaleString()) : value;

    return (
      <div className={`${config.bg} p-6 rounded-[2rem] border border-slate-100 shadow-sm transition-all hover:shadow-lg flex flex-col justify-between min-h-[140px]`}>
        <div>
          <span className="text-[10px] font-black uppercase tracking-widest opacity-50 mb-1 block">{title}</span>
          <h4 className={`text-2xl font-black tracking-tighter ${config.text}`}>
            {displayValue}<span className="text-xs ml-1 font-bold">{suffix}</span>
          </h4>
        </div>
        <div className="flex items-center gap-2 mt-3">
           <div className={`w-1 h-1 rounded-full ${config.text.replace('text-', 'bg-')}`}></div>
           <span className="text-[9px] font-bold text-slate-400">{config.label}</span>
        </div>
      </div>
    );
  };

  const DetailGrid = ({ stats }: { stats: any }) => (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-4">
      <MetricCard title="식자재비" value={stats.foodCost} type="exp" />
      <MetricCard title="식자재 비율" value={stats.foodRatio} type="ratio" suffix="%" />
      <MetricCard title="인건비" value={stats.laborCost} type="exp" />
      <MetricCard title="인건비 비율" value={stats.laborRatio} type="ratio" suffix="%" />
      <MetricCard title="고정 운영비" value={stats.fixedCost} type="exp" />
      <MetricCard title="고정비 비율" value={stats.fixedRatio} type="ratio" suffix="%" />
      <MetricCard title="비고정 지출" value={stats.variableOthers} type="exp" />
      <MetricCard title="순이익율" value={stats.rev > 0 ? (stats.profit / stats.rev) * 100 : 0} type="ratio" suffix="%" />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-20">
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <div>
              <h1 className="text-lg font-black tracking-tighter text-slate-900 leading-none">스마트 손익 분석</h1>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-6 py-2 rounded-xl bg-indigo-600 text-white text-xs font-black shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">
              기록
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-10 space-y-12">
        {/* 오늘 섹션 */}
        <section>
          <div className="flex items-end justify-between px-2 mb-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">오늘의 경영 실적</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">오늘 하루의 실적과 효율성 분석입니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="오늘의 매출" value={dashboardStats.today.rev} type="rev" />
            <MetricCard title="오늘의 지출" value={dashboardStats.today.exp} type="exp" />
            <MetricCard title="오늘의 순이익" value={dashboardStats.today.profit} type="profit" isMain />
          </div>
          <DetailGrid stats={dashboardStats.today} />
        </section>

        {/* 이번 달 누적 섹션 */}
        <section>
          <div className="flex items-end justify-between px-2 mb-6 border-l-4 border-indigo-500 pl-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">{new Date().getMonth() + 1}월 통합 누적 성과</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">이달 초부터 오늘까지의 누적 분석입니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="이번 달 총 매출" value={dashboardStats.month.rev} type="rev" />
            <MetricCard title="이번 달 총 지출" value={dashboardStats.month.exp} type="exp" />
            <MetricCard title="이번 달 총 순이익" value={dashboardStats.month.profit} type="profit" isMain />
          </div>
          <DetailGrid stats={dashboardStats.month} />
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
          {/* 최근 거래 내역 테이블 */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-widest">{entries.length}건</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-8 py-5">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-0.5 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-3">
                          <span className={`font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="opacity-0 group-hover:opacity-100 p-1 text-rose-300 hover:text-rose-600">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-6">
                  <h3 className="text-2xl font-black tracking-tight">시스템 관리</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setIsStaffModalOpen(true)} className="p-5 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">직원 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">인사 정보 설정</span>
                    </button>
                    <button onClick={() => setIsVendorModalOpen(true)} className="p-5 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">거래처 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">공급망 리스트</span>
                    </button>
                  </div>
                  <div className="p-6 rounded-2xl bg-indigo-600">
                    <div className="flex justify-between items-center">
                      <div>
                        <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">일일 고정 지출액</span>
                        <h4 className="text-2xl font-black mt-1">-{Math.round(dailyFixedOverhead).toLocaleString()}원</h4>
                      </div>
                      <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white/10 p-2 rounded-lg hover:bg-white/20 transition-all text-white text-xs font-bold">
                        수정
                      </button>
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      </main>

      {/* 모달창 섹션 */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">고정 지출 설정</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddFixedExpense} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="항목명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="category" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">비고정지출</option>
                </select>
              </div>
              <input name="amount" type="number" required placeholder="월 금액" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-black text-lg" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black hover:bg-black transition-all">
                항목 추가
              </button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{item.name} ({item.monthlyAmount.toLocaleString()}원)</span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">직원 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="이름" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="type" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="급여" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black">직원 등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">거래처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <input name="name" required placeholder="업체명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black">업체 등록</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const dailyFixedOverhead = useMemo(() => {
    return (monthlyLaborFixed + monthlyFixedCostOnly) / 30;
  }, [monthlyLaborFixed, monthlyFixedCostOnly]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);

    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    const foodCost = filteredEntries.filter(e => e.category === '식자재').reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = filteredEntries.filter(e => e.category === '인건비').reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = filteredEntries.filter(e => 
      e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category)
    ).reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev,
      exp: totalExp,
      profit: rev - totalExp,
      foodCost,
      laborCost: totalLabor,
      fixedCost: fixedExpensePart,
      variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (fixedExpensePart / rev) * 100 : 0,
      actualEntries: filteredEntries
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));

    return {
      today: calculateStats(todayEntries, 1),
      month: calculateStats(monthEntries, currentDayOfMonth)
    };
  }, [entries, dailyFixedOverhead, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  const handleAddEntry = (newEntry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...newEntry, id: `entry-${Date.now()}` }]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleAddFixedExpense = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    setFixedExpenseItems(prev => [...prev, { 
      id: `fixed-${Date.now()}`, 
      name: formData.get('name') as string,
      defaultCategory: formData.get('category') as any,
      monthlyAmount: Number(formData.get('amount'))
    }]);
    (e.target as HTMLFormElement).reset();
  };

  const MetricCard = ({ title, value, type, isMain, suffix = "원" }: { title: string, value: number | string, type: 'rev' | 'exp' | 'profit' | 'ratio', isMain?: boolean, suffix?: string }) => {
    const configs = {
      rev: { bg: 'bg-white', text: 'text-indigo-600', label: '수익' },
      exp: { bg: 'bg-white', text: 'text-rose-500', label: '지출' },
      profit: { bg: isMain ? 'bg-slate-900' : 'bg-emerald-500', text: 'text-white', label: '결과' },
      ratio: { bg: 'bg-slate-50', text: 'text-slate-900', label: '비율' }
    };
    const config = configs[type];
    const displayValue = typeof value === 'number' ? (type === 'ratio' ? value.toFixed(1) : value.toLocaleString()) : value;

    return (
      <div className={`${config.bg} p-6 rounded-[2rem] border border-slate-100 shadow-sm transition-all hover:shadow-lg flex flex-col justify-between min-h-[140px]`}>
        <div>
          <span className="text-[10px] font-black uppercase tracking-widest opacity-50 mb-1 block">{title}</span>
          <h4 className={`text-2xl font-black tracking-tighter ${config.text}`}>
            {displayValue}<span className="text-xs ml-1 font-bold">{suffix}</span>
          </h4>
        </div>
        <div className="flex items-center gap-2 mt-3">
           <div className={`w-1 h-1 rounded-full ${config.text.replace('text-', 'bg-')}`}></div>
           <span className="text-[9px] font-bold text-slate-400">{config.label}</span>
        </div>
      </div>
    );
  };

  const DetailGrid = ({ stats, showItems }: { stats: any, showItems?: boolean }) => {
    const expenseItems = stats.actualEntries.filter((e: PLEntry) => e.type === '지출');

    return (
      <div className="space-y-4 mt-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <MetricCard title="식자재비" value={stats.foodCost} type="exp" />
          <MetricCard title="식자재 비율" value={stats.foodRatio} type="ratio" suffix="%" />
          <MetricCard title="인건비" value={stats.laborCost} type="exp" />
          <MetricCard title="인건비 비율" value={stats.laborRatio} type="ratio" suffix="%" />
          <MetricCard title="고정 운영비" value={stats.fixedCost} type="exp" />
          <MetricCard title="고정비 비율" value={stats.fixedRatio} type="ratio" suffix="%" />
          <MetricCard title="비고정 지출" value={stats.variableOthers} type="exp" />
          <MetricCard title="순이익율" value={stats.rev > 0 ? (stats.profit / stats.rev) * 100 : 0} type="ratio" suffix="%" />
        </div>

        {showItems && expenseItems.length > 0 && (
          <div className="bg-white rounded-[2rem] border border-slate-100 p-6 shadow-sm">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-rose-500"></span>
              오늘의 개별 지출 항목 ({expenseItems.length}건)
            </h4>
            <div className="space-y-2">
              {expenseItems.map((item: PLEntry) => (
                <div key={item.id} className="flex items-center justify-between p-4 bg-slate-50/50 rounded-xl hover:bg-slate-50 transition-colors">
                  <div className="flex items-center gap-4">
                    <span className="text-[9px] font-black px-2 py-1 bg-white border border-slate-100 rounded-lg text-slate-500 uppercase">{item.category}</span>
                    <span className="text-sm font-bold text-slate-700">{item.description}</span>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className="text-sm font-black text-rose-500">-{item.amount.toLocaleString()}원</span>
                    <button onClick={() => handleDeleteEntry(item.id)} className="text-slate-300 hover:text-rose-500 transition-colors">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  </div>
                </div>
              ))}
              <div className="p-4 bg-indigo-50/30 rounded-xl border border-dashed border-indigo-100">
                <p className="text-[10px] font-bold text-indigo-400 text-center">
                  * 시스템 자동 계산된 고정비(인건비/임대료 등) {Math.round(stats.fixedCost).toLocaleString()}원은 별도 합산되어 있습니다.
                </p>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-20">
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <div>
              <h1 className="text-lg font-black tracking-tighter text-slate-900 leading-none">스마트 손익 분석</h1>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-6 py-2 rounded-xl bg-indigo-600 text-white text-xs font-black shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">
              기록
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-10 space-y-12">
        {/* 오늘 섹션 */}
        <section>
          <div className="flex items-end justify-between px-2 mb-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">오늘의 경영 실적</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">오늘 하루 발생한 모든 지출과 매출 내역입니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="오늘의 매출" value={dashboardStats.today.rev} type="rev" />
            <MetricCard title="오늘의 지출" value={dashboardStats.today.exp} type="exp" />
            <MetricCard title="오늘의 순이익" value={dashboardStats.today.profit} type="profit" isMain />
          </div>
          <DetailGrid stats={dashboardStats.today} showItems={true} />
        </section>

        {/* 이번 달 누적 섹션 */}
        <section>
          <div className="flex items-end justify-between px-2 mb-6 border-l-4 border-indigo-500 pl-6">
            <div>
              <h2 className="text-3xl font-black tracking-tighter text-slate-900">{new Date().getMonth() + 1}월 통합 누적 성과</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">이달 초부터 오늘까지의 누적 분석입니다.</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <MetricCard title="이번 달 총 매출" value={dashboardStats.month.rev} type="rev" />
            <MetricCard title="이번 달 총 지출" value={dashboardStats.month.exp} type="exp" />
            <MetricCard title="이번 달 총 순이익" value={dashboardStats.month.profit} type="profit" isMain />
          </div>
          <DetailGrid stats={dashboardStats.month} />
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">전체 거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-widest">{entries.length}건</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-8 py-5">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-0.5 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-3">
                          <span className={`font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="opacity-0 group-hover:opacity-100 p-1 text-rose-300 hover:text-rose-600">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-6">
                  <h3 className="text-2xl font-black tracking-tight">시스템 설정</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setIsStaffModalOpen(true)} className="p-5 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">직원 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">인사 정보</span>
                    </button>
                    <button onClick={() => setIsVendorModalOpen(true)} className="p-5 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">거래처 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">업체 리스트</span>
                    </button>
                  </div>
                  <div className="p-6 rounded-2xl bg-indigo-600">
                    <div className="flex justify-between items-center">
                      <div>
                        <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">일일 고정 지출액</span>
                        <h4 className="text-2xl font-black mt-1">-{Math.round(dailyFixedOverhead).toLocaleString()}원</h4>
