      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">고정 지출 설정</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleAddFixedExpense} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="항목명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="category" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">비고정지출</option>
                </select>
              </div>
              <input name="amount" type="number" required placeholder="월 금액" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-black text-lg" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black hover:bg-black transition-all">
                항목 추가
              </button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{item.name} ({item.monthlyAmount.toLocaleString()}원)</span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">직원 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="이름" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="type" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="급여" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black">직원 등록</button>
            </form>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">거래처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <input name="name" required placeholder="업체명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black">업체 등록</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);

    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    const foodEntries = filteredEntries.filter(e => e.category === '식자재');
    const laborEntries = filteredEntries.filter(e => e.category === '인건비');
    const fixedManualEntries = filteredEntries.filter(e => ['월세', '관리비'].includes(e.category));
    const otherEntries = filteredEntries.filter(e => 
      e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category)
    );

    const foodCost = foodEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = laborEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const manualFixed = fixedManualEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = otherEntries.reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalFixed = fixedExpensePart + manualFixed;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev,
      exp: totalExp,
      profit: rev - totalExp,
      foodCost,
      laborCost: totalLabor,
      fixedCost: totalFixed,
      variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (totalFixed / rev) * 100 : 0,
      categories: {
        food: { items: foodEntries, total: foodCost },
        labor: { items: laborEntries, total: totalLabor, auto: laborFixedPart },
        fixed: { items: fixedManualEntries, total: totalFixed, auto: fixedExpensePart },
        others: { items: otherEntries, total: variableOthers }
      }
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));

    return {
      today: calculateStats(todayEntries, 1),
      month: calculateStats(monthEntries, currentDayOfMonth)
    };
  }, [entries, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const MetricCard = ({ title, value, type, suffix = "원", subValue }: { title: string, value: number, type: 'rev' | 'exp' | 'ratio', suffix?: string, subValue?: string }) => {
    const configs = {
      rev: { text: 'text-indigo-600' },
      exp: { text: 'text-rose-500' },
      ratio: { text: 'text-slate-900' }
    };
    return (
      <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
        <span className="text-[10px] font-black uppercase text-slate-400 block mb-1">{title}</span>
        <div className={`text-xl font-black ${configs[type].text}`}>
          {type === 'ratio' ? value.toFixed(1) : value.toLocaleString()}<span className="text-xs ml-0.5">{suffix}</span>
        </div>
        {subValue && <div className="text-[9px] font-bold text-slate-400 mt-1 uppercase">{subValue}</div>}
      </div>
    );
  };

  const CategorySection = ({ title, stats, items, autoValue, type = 'exp' }: { title: string, stats: number, items: PLEntry[], autoValue?: number, type?: 'exp' | 'ratio' }) => (
    <div className="flex flex-col h-full bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
      <div className="p-5 border-b border-slate-50 bg-slate-50/50">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">{title}</span>
        <div className={`text-xl font-black ${type === 'exp' ? 'text-rose-500' : 'text-slate-900'}`}>
          {stats.toLocaleString()}{type === 'exp' ? '원' : '%'}
        </div>
      </div>
      <div className="p-4 flex-1 overflow-y-auto max-h-[180px] space-y-2 custom-scrollbar">
        {autoValue && autoValue > 0 && (
          <div className="px-3 py-2 bg-indigo-50/50 rounded-xl border border-dashed border-indigo-100 flex justify-between items-center">
            <span className="text-[10px] font-bold text-indigo-500">시스템 고정비 (자동)</span>
            <span className="text-[10px] font-black text-indigo-600">-{Math.round(autoValue).toLocaleString()}</span>
          </div>
        )}
        {items.length > 0 ? (
          items.map(item => (
            <div key={item.id} className="flex items-center justify-between p-3 bg-slate-50/50 rounded-xl hover:bg-slate-50 transition-colors group">
              <div className="flex flex-col min-w-0 mr-2">
                <span className="text-[10px] font-black text-slate-400 truncate">{item.date.slice(8)}일 {item.description}</span>
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <span className="text-[10px] font-black text-rose-500">-{item.amount.toLocaleString()}</span>
                <button onClick={() => handleDeleteEntry(item.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          ))
        ) : (
          !autoValue && <p className="text-[10px] text-slate-300 font-bold text-center py-4">기록된 내역 없음</p>
        )}
      </div>
    </div>
  );

  const AnalysisDashboard = ({ stats, title, subtitle }: { stats: any, title: string, subtitle: string }) => (
    <section className="space-y-6">
      <div className="flex items-end justify-between px-2">
        <div>
          <h2 className="text-3xl font-black tracking-tighter text-slate-900">{title}</h2>
          <p className="text-slate-400 text-sm font-medium mt-1">{subtitle}</p>
        </div>
      </div>

      {/* 주요 지표 상단 */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex justify-between items-center">
          <div>
            <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">총 수익</span>
            <div className="text-3xl font-black tracking-tighter text-indigo-400">{stats.rev.toLocaleString()}<span className="text-sm ml-1">원</span></div>
          </div>
          <div className="text-right">
             <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">총 지출</span>
             <div className="text-2xl font-black tracking-tighter text-rose-400">-{stats.exp.toLocaleString()}</div>
          </div>
        </div>
        <div className="bg-emerald-500 p-8 rounded-[2.5rem] text-white">
           <span className="text-[10px] font-black uppercase text-emerald-100 tracking-widest block mb-1">실제 순이익</span>
           <div className="text-3xl font-black tracking-tighter">{stats.profit.toLocaleString()}<span className="text-sm ml-1">원</span></div>
        </div>
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100">
           <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">순이익율</span>
           <div className="text-3xl font-black tracking-tighter text-slate-900">{(stats.rev > 0 ? (stats.profit / stats.rev) * 100 : 0).toFixed(1)}<span className="text-sm ml-1">%</span></div>
        </div>
      </div>

      {/* 카테고리별 상세 내역 (지출 및 비율) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="space-y-3">
          <CategorySection title="식자재비" stats={stats.foodCost} items={stats.categories.food.items} />
          <MetricCard title="식자재 비중" value={stats.foodRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="인건비" stats={stats.laborCost} items={stats.categories.labor.items} autoValue={stats.categories.labor.auto} />
          <MetricCard title="인건비 비중" value={stats.laborRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="고정 운영비" stats={stats.fixedCost} items={stats.categories.fixed.items} autoValue={stats.categories.fixed.auto} />
          <MetricCard title="고정비 비중" value={stats.fixedRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="비고정/기타 지출" stats={stats.variableOthers} items={stats.categories.others.items} />
          <MetricCard title="기타 지출 비중" value={stats.rev > 0 ? (stats.variableOthers / stats.rev) * 100 : 0} type="ratio" suffix="%" />
        </div>
      </div>
    </section>
  );

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-20">
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <h1 className="text-lg font-black tracking-tighter text-slate-900 leading-none">Smart P&L Master</h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              고정비 설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-6 py-2 rounded-xl bg-indigo-600 text-white text-xs font-black shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">
              기록하기
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-10 space-y-20">
        <AnalysisDashboard 
          stats={dashboardStats.today} 
          title="오늘의 경영 리포트" 
          subtitle="일일 카테고리별 지출 상세 내역 및 효율성 분석입니다."
        />

        <AnalysisDashboard 
          stats={dashboardStats.month} 
          title={`${new Date().getMonth() + 1}월 통합 성과 보고`} 
          subtitle="이번 달 누적된 모든 지출 항목과 매출 대비 비중 분석입니다."
        />

        {/* 하단 관리 섹션 */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-10 border-t border-slate-200">
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">전체 거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-widest">{entries.length}건</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-8 py-5">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-0.5 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-3">
                          <span className={`font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="opacity-0 group-hover:opacity-100 p-1 text-rose-300 hover:text-rose-600">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-8">
                  <h3 className="text-2xl font-black tracking-tight">마스터 시스템 설정</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setIsStaffModalOpen(true)} className="p-6 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">직원 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">급여 시스템</span>
                    </button>
                    <button onClick={() => setIsVendorModalOpen(true)} className="p-6 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">거래처 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">공급망 리스트</span>
                    </button>
                  </div>
                  <div className="p-8 rounded-[2rem] bg-indigo-600">
                    <div className="flex justify-between items-center">
                      <div>
                        <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">일일 자동 고정비</span>
                        <h4 className="text-3xl font-black mt-1">-{Math.round((monthlyLaborFixed + monthlyFixedCostOnly) / 30).toLocaleString()}원</h4>
                      </div>
                      <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white/10 p-3 rounded-xl hover:bg-white/20 transition-all text-white text-xs font-bold">
                        항목 수정
                      </button>
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      </main>

      {/* 모달 창들은 이전과 동일하게 유지 (EntryModal 포함) */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">고정 지출 설정</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setFixedExpenseItems(prev => [...prev, { 
                id: `fixed-${Date.now()}`, 
                name: formData.get('name') as string,
                defaultCategory: formData.get('category') as any,
                monthlyAmount: Number(formData.get('amount'))
              }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="항목명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="category" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">비고정지출</option>
                </select>
              </div>
              <input name="amount" type="number" required placeholder="월 고정 금액" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-black text-lg" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black hover:bg-black transition-all">
                시스템 등록
              </button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{item.name} ({item.monthlyAmount.toLocaleString()}원)</span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">직원 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="type" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="월급 또는 시급" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black">직원 추가</button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {staffList.map(s => (
                <div key={s.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{s.name} ({s.type}: {s.basePay.toLocaleString()}원)</span>
                  <button onClick={() => setStaffList(l => l.filter(i => i.id !== s.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">거래처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <input name="name" required placeholder="업체명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black">거래처 추가</button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {vendorList.map(v => (
                <div key={v.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{v.name}</span>
                  <button onClick={() => setVendorList(l => l.filter(i => i.id !== v.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);

    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    const foodEntries = filteredEntries.filter(e => e.category === '식자재');
    const laborEntries = filteredEntries.filter(e => e.category === '인건비');
    const fixedManualEntries = filteredEntries.filter(e => ['월세', '관리비'].includes(e.category));
    const otherEntries = filteredEntries.filter(e => 
      e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category)
    );

    const foodCost = foodEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = laborEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const manualFixed = fixedManualEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = otherEntries.reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalFixed = fixedExpensePart + manualFixed;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev,
      exp: totalExp,
      profit: rev - totalExp,
      foodCost,
      laborCost: totalLabor,
      fixedCost: totalFixed,
      variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (totalFixed / rev) * 100 : 0,
      categories: {
        food: { items: foodEntries, total: foodCost },
        labor: { items: laborEntries, total: totalLabor, auto: laborFixedPart },
        fixed: { items: fixedManualEntries, total: totalFixed, auto: fixedExpensePart },
        others: { items: otherEntries, total: variableOthers }
      }
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));

    return {
      today: calculateStats(todayEntries, 1),
      month: calculateStats(monthEntries, currentDayOfMonth)
    };
  }, [entries, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  // Added handleAddEntry to fix the reference error on line 366
  const handleAddEntry = (entry: Omit<PLEntry, 'id'>) => {
    const newEntry: PLEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
    };
    setEntries(prev => [...prev, newEntry]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const MetricCard = ({ title, value, type, suffix = "원", subValue }: { title: string, value: number, type: 'rev' | 'exp' | 'ratio', suffix?: string, subValue?: string }) => {
    const configs = {
      rev: { text: 'text-indigo-600' },
      exp: { text: 'text-rose-500' },
      ratio: { text: 'text-slate-900' }
    };
    return (
      <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
        <span className="text-[10px] font-black uppercase text-slate-400 block mb-1">{title}</span>
        <div className={`text-xl font-black ${configs[type].text}`}>
          {type === 'ratio' ? value.toFixed(1) : value.toLocaleString()}<span className="text-xs ml-0.5">{suffix}</span>
        </div>
        {subValue && <div className="text-[9px] font-bold text-slate-400 mt-1 uppercase">{subValue}</div>}
      </div>
    );
  };

  const CategorySection = ({ title, stats, items, autoValue, type = 'exp' }: { title: string, stats: number, items: PLEntry[], autoValue?: number, type?: 'exp' | 'ratio' }) => (
    <div className="flex flex-col h-full bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
      <div className="p-5 border-b border-slate-50 bg-slate-50/50">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">{title}</span>
        <div className={`text-xl font-black ${type === 'exp' ? 'text-rose-500' : 'text-slate-900'}`}>
          {stats.toLocaleString()}{type === 'exp' ? '원' : '%'}
        </div>
      </div>
      <div className="p-4 flex-1 overflow-y-auto max-h-[180px] space-y-2 custom-scrollbar">
        {autoValue && autoValue > 0 && (
          <div className="px-3 py-2 bg-indigo-50/50 rounded-xl border border-dashed border-indigo-100 flex justify-between items-center">
            <span className="text-[10px] font-bold text-indigo-500">시스템 고정비 (자동)</span>
            <span className="text-[10px] font-black text-indigo-600">-{Math.round(autoValue).toLocaleString()}</span>
          </div>
        )}
        {items.length > 0 ? (
          items.map(item => (
            <div key={item.id} className="flex items-center justify-between p-3 bg-slate-50/50 rounded-xl hover:bg-slate-50 transition-colors group">
              <div className="flex flex-col min-w-0 mr-2">
                <span className="text-[10px] font-black text-slate-400 truncate">{item.date.slice(8)}일 {item.description}</span>
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <span className="text-[10px] font-black text-rose-500">-{item.amount.toLocaleString()}</span>
                <button onClick={() => handleDeleteEntry(item.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          ))
        ) : (
          !autoValue && <p className="text-[10px] text-slate-300 font-bold text-center py-4">기록된 내역 없음</p>
        )}
      </div>
    </div>
  );

  const AnalysisDashboard = ({ stats, title, subtitle }: { stats: any, title: string, subtitle: string }) => (
    <section className="space-y-6">
      <div className="flex items-end justify-between px-2">
        <div>
          <h2 className="text-3xl font-black tracking-tighter text-slate-900">{title}</h2>
          <p className="text-slate-400 text-sm font-medium mt-1">{subtitle}</p>
        </div>
      </div>

      {/* 주요 지표 상단 */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex justify-between items-center">
          <div>
            <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">총 수익</span>
            <div className="text-3xl font-black tracking-tighter text-indigo-400">{stats.rev.toLocaleString()}<span className="text-sm ml-1">원</span></div>
          </div>
          <div className="text-right">
             <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">총 지출</span>
             <div className="text-2xl font-black tracking-tighter text-rose-400">-{stats.exp.toLocaleString()}</div>
          </div>
        </div>
        <div className="bg-emerald-500 p-8 rounded-[2.5rem] text-white">
           <span className="text-[10px] font-black uppercase text-emerald-100 tracking-widest block mb-1">실제 순이익</span>
           <div className="text-3xl font-black tracking-tighter">{stats.profit.toLocaleString()}<span className="text-sm ml-1">원</span></div>
        </div>
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100">
           <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">순이익율</span>
           <div className="text-3xl font-black tracking-tighter text-slate-900">{(stats.rev > 0 ? (stats.profit / stats.rev) * 100 : 0).toFixed(1)}<span className="text-sm ml-1">%</span></div>
        </div>
      </div>

      {/* 카테고리별 상세 내역 (지출 및 비율) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="space-y-3">
          <CategorySection title="식자재비" stats={stats.foodCost} items={stats.categories.food.items} />
          <MetricCard title="식자재 비중" value={stats.foodRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="인건비" stats={stats.laborCost} items={stats.categories.labor.items} autoValue={stats.categories.labor.auto} />
          <MetricCard title="인건비 비중" value={stats.laborRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="고정 운영비" stats={stats.fixedCost} items={stats.categories.fixed.items} autoValue={stats.categories.fixed.auto} />
          <MetricCard title="고정비 비중" value={stats.fixedRatio} type="ratio" suffix="%" />
        </div>
        <div className="space-y-3">
          <CategorySection title="비고정/기타 지출" stats={stats.variableOthers} items={stats.categories.others.items} />
          <MetricCard title="기타 지출 비중" value={stats.rev > 0 ? (stats.variableOthers / stats.rev) * 100 : 0} type="ratio" suffix="%" />
        </div>
      </div>
    </section>
  );

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-20">
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <h1 className="text-lg font-black tracking-tighter text-slate-900 leading-none">Smart P&L Master</h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">
              고정비 설정
            </button>
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-6 py-2 rounded-xl bg-indigo-600 text-white text-xs font-black shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">
              기록하기
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-10 space-y-20">
        <AnalysisDashboard 
          stats={dashboardStats.today} 
          title="오늘의 경영 리포트" 
          subtitle="일일 카테고리별 지출 상세 내역 및 효율성 분석입니다."
        />

        <AnalysisDashboard 
          stats={dashboardStats.month} 
          title={`${new Date().getMonth() + 1}월 통합 성과 보고`} 
          subtitle="이번 달 누적된 모든 지출 항목과 매출 대비 비중 분석입니다."
        />

        {/* 하단 관리 섹션 */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-10 border-t border-slate-200">
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-lg">전체 거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-widest">{entries.length}건</span>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-8 py-5">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-0.5 uppercase tracking-tighter">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-3">
                          <span className={`font-black text-sm ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="opacity-0 group-hover:opacity-100 p-1 text-rose-300 hover:text-rose-600">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-8">
                  <h3 className="text-2xl font-black tracking-tight">마스터 시스템 설정</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setIsStaffModalOpen(true)} className="p-6 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">직원 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">급여 시스템</span>
                    </button>
                    <button onClick={() => setIsVendorModalOpen(true)} className="p-6 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-sm block">거래처 관리</span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase mt-1">공급망 리스트</span>
                    </button>
                  </div>
                  <div className="p-8 rounded-[2rem] bg-indigo-600">
                    <div className="flex justify-between items-center">
                      <div>
                        <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">일일 자동 고정비</span>
                        <h4 className="text-3xl font-black mt-1">-{Math.round((monthlyLaborFixed + monthlyFixedCostOnly) / 30).toLocaleString()}원</h4>
                      </div>
                      <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white/10 p-3 rounded-xl hover:bg-white/20 transition-all text-white text-xs font-bold">
                        항목 수정
                      </button>
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      </main>

      {/* 모달 창들은 이전과 동일하게 유지 (EntryModal 포함) */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">고정 지출 설정</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setFixedExpenseItems(prev => [...prev, { 
                id: `fixed-${Date.now()}`, 
                name: formData.get('name') as string,
                defaultCategory: formData.get('category') as any,
                monthlyAmount: Number(formData.get('amount'))
              }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="항목명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="category" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">비고정지출</option>
                </select>
              </div>
              <input name="amount" type="number" required placeholder="월 고정 금액" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-black text-lg" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black hover:bg-black transition-all">
                시스템 등록
              </button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{item.name} ({item.monthlyAmount.toLocaleString()}원)</span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleAddEntry} staffList={staffList} vendorList={vendorList} fixedExpenseItems={fixedExpenseItems} />

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">직원 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
                <select name="type" className="px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="월급 또는 시급" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-black">직원 추가</button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {staffList.map(s => (
                <div key={s.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{s.name} ({s.type}: {s.basePay.toLocaleString()}원)</span>
                  <button onClick={() => setStaffList(l => l.filter(i => i.id !== s.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-slate-900 tracking-tighter">거래처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-2 rounded-xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-8">
              <input name="name" required placeholder="업체명" className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black">거래처 추가</button>
            </form>
            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
              {vendorList.map(v => (
                <div key={v.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="font-bold text-xs text-slate-700">{v.name}</span>
                  <button onClick={() => setVendorList(l => l.filter(i => i.id !== v.id))} className="text-rose-400 text-[10px] font-black">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);

    // 일별/월별 안분 고정비
    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    // 카테고리별 분류
    const foodEntries = filteredEntries.filter(e => e.category === '식자재');
    const laborEntries = filteredEntries.filter(e => e.category === '인건비');
    const fixedManualEntries = filteredEntries.filter(e => ['월세', '관리비'].includes(e.category));
    const otherEntries = filteredEntries.filter(e => 
      e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category)
    );

    const foodCost = foodEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = laborEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const manualFixed = fixedManualEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = otherEntries.reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalFixed = fixedExpensePart + manualFixed;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev,
      exp: totalExp,
      profit: rev - totalExp,
      foodCost,
      laborCost: totalLabor,
      fixedCost: totalFixed,
      variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (totalFixed / rev) * 100 : 0,
      othersRatio: rev > 0 ? (variableOthers / rev) * 100 : 0,
      categories: {
        food: { items: foodEntries, total: foodCost },
        labor: { items: laborEntries, total: totalLabor, auto: laborFixedPart },
        fixed: { items: fixedManualEntries, total: totalFixed, auto: fixedExpensePart },
        others: { items: otherEntries, total: variableOthers }
      }
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));

    return {
      today: calculateStats(todayEntries, 1),
      month: calculateStats(monthEntries, currentDayOfMonth)
    };
  }, [entries, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  const handleAddEntry = (entry: Omit<PLEntry, 'id'>) => {
    const newEntry: PLEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
    };
    setEntries(prev => [...prev, newEntry]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const CategoryAnalysisCard = ({ title, total, ratio, items, autoValue, colorClass }: { 
    title: string, total: number, ratio: number, items: PLEntry[], autoValue?: number, colorClass: string 
  }) => (
    <div className="flex flex-col bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm transition-all hover:shadow-md">
      <div className={`p-5 border-b border-slate-50 ${colorClass} bg-opacity-5`}>
        <div className="flex justify-between items-start mb-2">
          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{title}</span>
          <span className="text-[11px] font-black text-slate-900 bg-white px-2 py-0.5 rounded-full border border-slate-100 shadow-sm">
            {ratio.toFixed(1)}%
          </span>
        </div>
        <div className="text-xl font-black text-slate-900">
          {total.toLocaleString()}<span className="text-xs ml-0.5">원</span>
        </div>
      </div>
      <div className="p-4 flex-1 overflow-y-auto max-h-[220px] space-y-2 custom-scrollbar bg-slate-50/20">
        {autoValue && autoValue > 0 && (
          <div className="px-3 py-2 bg-indigo-50/50 rounded-xl border border-dashed border-indigo-100 flex justify-between items-center animate-pulse">
            <span className="text-[10px] font-bold text-indigo-500">시스템 안분 고정비</span>
            <span className="text-[10px] font-black text-indigo-600">-{Math.round(autoValue).toLocaleString()}</span>
          </div>
        )}
        {items.length > 0 ? (
          items.map(item => (
            <div key={item.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-slate-50 group transition-all hover:border-indigo-100">
              <div className="flex flex-col min-w-0">
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">
                  {item.date.slice(8)}일 • {item.category}
                </span>
                <span className="text-[11px] font-bold text-slate-700 truncate">{item.description}</span>
              </div>
              <div className="flex items-center gap-2 ml-2">
                <span className="text-[11px] font-black text-rose-500">-{item.amount.toLocaleString()}</span>
                <button onClick={() => handleDeleteEntry(item.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 transition-all">
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          ))
        ) : (
          !autoValue && <div className="text-center py-8 text-slate-300 font-bold text-[10px]">내역 없음</div>
        )}
      </div>
    </div>
  );

  const AnalysisReport = ({ stats, title, subtitle }: { stats: any, title: string, subtitle: string }) => (
    <section className="space-y-8">
      <div className="flex items-end justify-between px-2">
        <div>
          <h2 className="text-4xl font-black tracking-tighter text-slate-900">{title}</h2>
          <p className="text-slate-400 text-sm font-medium mt-1">{subtitle}</p>
        </div>
        <div className="hidden md:flex gap-4">
           <div className="text-right">
              <span className="text-[10px] font-black text-slate-300 uppercase block">수익율</span>
              <span className="text-lg font-black text-emerald-500">{(stats.rev > 0 ? (stats.profit / stats.rev) * 100 : 0).toFixed(1)}%</span>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <CategoryAnalysisCard 
          title="식자재 지출" 
          total={stats.foodCost} 
          ratio={stats.foodRatio} 
          items={stats.categories.food.items} 
          colorClass="bg-emerald-500"
        />
        <CategoryAnalysisCard 
          title="인건비 지출" 
          total={stats.laborCost} 
          ratio={stats.laborRatio} 
          items={stats.categories.labor.items} 
          autoValue={stats.categories.labor.auto}
          colorClass="bg-orange-500"
        />
        <CategoryAnalysisCard 
          title="고정운영비" 
          total={stats.fixedCost} 
          ratio={stats.fixedRatio} 
          items={stats.categories.fixed.items} 
          autoValue={stats.categories.fixed.auto}
          colorClass="bg-blue-500"
        />
        <CategoryAnalysisCard 
          title="비고정/기타" 
          total={stats.variableOthers} 
          ratio={stats.othersRatio} 
          items={stats.categories.others.items} 
          colorClass="bg-slate-500"
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-xl flex flex-col justify-center">
          <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-1">총 매출</span>
          <div className="text-4xl font-black text-indigo-400 tracking-tighter">{stats.rev.toLocaleString()}<span className="text-lg ml-1 font-bold">원</span></div>
        </div>
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex flex-col justify-center shadow-sm">
          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-1">총 지출 (고정비 포함)</span>
          <div className="text-3xl font-black text-rose-500 tracking-tighter">-{stats.exp.toLocaleString()}<span className="text-sm ml-1 font-bold">원</span></div>
        </div>
        <div className={`p-8 rounded-[2.5rem] flex flex-col justify-center shadow-xl ${stats.profit >= 0 ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
          <span className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-1">예상 영업이익</span>
          <div className="text-4xl font-black tracking-tighter">{stats.profit.toLocaleString()}<span className="text-lg ml-1 font-bold">원</span></div>
        </div>
      </div>
    </section>
  );

  return (
    <div className="min-h-screen bg-[#f8f9fc] text-slate-900 font-sans selection:bg-indigo-100 pb-32">
      <nav className="sticky top-0 z-50 bg-white/70 backdrop-blur-2xl border-b border-slate-100/50 px-6 py-4">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-2xl shadow-slate-200">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <h1 className="text-xl font-black tracking-tighter text-slate-900">Smart P&L Analyst</h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setIsFixedExpenseModalOpen(true)} className="hidden md:flex px-5 py-2.5 rounded-xl border border-slate-200 bg-white text-xs font-black text-slate-600 hover:bg-slate-50 transition-all">설정</button>
            <button onClick={() => setIsModalOpen(true)} className="px-7 py-2.5 rounded-xl bg-indigo-600 text-white text-xs font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">신규 기록</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-12 space-y-24">
        <AnalysisReport 
          stats={dashboardStats.today} 
          title="오늘의 실적 지표" 
          subtitle="일일 지출 분류별 상세 분석 및 매출 비중 리포트입니다."
        />

        <div className="pt-10 border-t border-slate-100">
          <AnalysisReport 
            stats={dashboardStats.month} 
            title={`${new Date().getMonth() + 1}월 누적 성과`} 
            subtitle="이번 달 초부터 현재까지의 통합 지출 내역 및 운영 효율성 분석입니다."
          />
        </div>

        {/* 하단 관리 섹션 */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 pt-16 border-t border-slate-100">
          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
            <div className="px-10 py-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-800 text-xl tracking-tight">전체 거래 타임라인</h3>
              <span className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest">{entries.length}건의 기록</span>
            </div>
            <div className="overflow-y-auto max-h-[500px] custom-scrollbar">
              <table className="w-full text-left">
                <tbody className="divide-y divide-slate-50">
                  {entries.sort((a,b) => b.date.localeCompare(a.date)).map(entry => (
                    <tr key={entry.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-10 py-6">
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-300 mb-1 uppercase">{entry.date.slice(5).replace('-', '/')}</span>
                          <span className="text-sm font-black text-slate-700">{entry.description}</span>
                        </div>
                      </td>
                      <td className="px-10 py-6">
                        <span className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase ${entry.type === '매출' ? 'bg-indigo-50 text-indigo-600' : 'bg-rose-50 text-rose-600'}`}>
                          {entry.category}
                        </span>
                      </td>
                      <td className="px-10 py-6 text-right">
                        <div className="flex items-center justify-end gap-4">
                          <span className={`font-black text-md ${entry.type === '매출' ? 'text-indigo-600' : 'text-slate-900'}`}>
                            {entry.type === '매출' ? '+' : '-'}{entry.amount.toLocaleString()}
                          </span>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="opacity-0 group-hover:opacity-100 p-2 text-rose-300 hover:text-rose-600 transition-all">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="space-y-8">
            <div className="bg-slate-900 rounded-[3rem] p-12 text-white shadow-2xl relative overflow-hidden">
               <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-[100px] rounded-full"></div>
               <div className="relative z-10 space-y-10">
                  <h3 className="text-3xl font-black tracking-tight">시스템 환경 설정</h3>
                  <div className="grid grid-cols-2 gap-5">
                    <button onClick={() => setIsStaffModalOpen(true)} className="p-8 rounded-[2.5rem] bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-lg block">직원 관리</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase mt-2 block tracking-widest">급여 및 인건비</span>
                    </button>
                    <button onClick={() => setIsVendorModalOpen(true)} className="p-8 rounded-[2.5rem] bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-left">
                      <span className="font-black text-lg block">거래처 관리</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase mt-2 block tracking-widest">식자재 공급망</span>
                    </button>
                  </div>
                  <div className="p-10 rounded-[2.5rem] bg-indigo-600 shadow-2xl shadow-indigo-900/40">
                    <div className="flex justify-between items-center">
                      <div>
                        <span className="text-[11px] font-black text-indigo-200 uppercase tracking-widest block mb-2">총 고정비 (월간)</span>
                        <h4 className="text-4xl font-black">{(monthlyLaborFixed + monthlyFixedCostOnly).toLocaleString()}<span className="text-lg ml-1 font-bold">원</span></h4>
                      </div>
                      <button onClick={() => setIsFixedExpenseModalOpen(true)} className="bg-white/10 p-4 rounded-2xl hover:bg-white/20 transition-all text-white font-black text-xs">
                        항목 수정
                      </button>
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      </main>

      {/* 모달 창 구성 */}
      {isFixedExpenseModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">고정 지출 설정</h2>
              <button onClick={() => setIsFixedExpenseModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setFixedExpenseItems(prev => [...prev, { 
                id: `fixed-${Date.now()}`, 
                name: formData.get('name') as string,
                defaultCategory: formData.get('category') as any,
                monthlyAmount: Number(formData.get('amount'))
              }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-5 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="항목명" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500" />
                <select name="category" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500">
                  <option value="월세">월세</option>
                  <option value="관리비">관리비</option>
                  <option value="비고정지출">기타 고정비</option>
                </select>
              </div>
              <input name="amount" type="number" required placeholder="월 고정 금액 (원)" className="w-full px-6 py-4 bg-slate-50 rounded-2xl outline-none font-black text-xl focus:ring-2 focus:ring-indigo-500" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black hover:bg-black transition-all">시스템 등록</button>
            </form>
            <div className="space-y-3 max-h-48 overflow-y-auto custom-scrollbar">
              {fixedExpenseItems.map(item => (
                <div key={item.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-transparent hover:border-slate-100">
                  <span className="font-bold text-sm text-slate-700">{item.name} ({item.monthlyAmount.toLocaleString()}원)</span>
                  <button onClick={() => setFixedExpenseItems(l => l.filter(i => i.id !== item.id))} className="text-rose-400 text-[10px] font-black uppercase hover:text-rose-600">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <EntryModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleAddEntry} 
        staffList={staffList} 
        vendorList={vendorList} 
        fixedExpenseItems={fixedExpenseItems} 
      />

      {/* 직원 및 거래처 모달 생략 - 이전 파일과 동일한 구조 유지 */}
      {isStaffModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">인사 관리</h2>
              <button onClick={() => setIsStaffModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setStaffList(prev => [...prev, { id: `s-${Date.now()}`, name: formData.get('name') as string, type: formData.get('type') as any, basePay: Number(formData.get('pay')) }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-10">
              <div className="grid grid-cols-2 gap-4">
                <input name="name" required placeholder="성함" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                <select name="type" className="px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm">
                  <option value="정규직">정규직</option>
                  <option value="알바">알바</option>
                </select>
              </div>
              <input name="pay" type="number" required placeholder="월급 또는 시급" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black">직원 추가</button>
            </form>
            <div className="space-y-3 max-h-48 overflow-y-auto custom-scrollbar">
              {staffList.map(s => (
                <div key={s.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl">
                  <span className="font-bold text-sm text-slate-700">{s.name} ({s.type}: {s.basePay.toLocaleString()}원)</span>
                  <button onClick={() => setStaffList(l => l.filter(i => i.id !== s.id))} className="text-rose-400 text-[10px] font-black uppercase hover:text-rose-600">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {isVendorModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">거래처 관리</h2>
              <button onClick={() => setIsVendorModalOpen(false)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget as HTMLFormElement);
              setVendorList(prev => [...prev, { id: `v-${Date.now()}`, name: formData.get('name') as string }]);
              (e.target as HTMLFormElement).reset();
            }} className="space-y-4 mb-10">
              <input name="name" required placeholder="업체명 (예: 식자재마트)" className="w-full px-5 py-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
              <button type="submit" className="w-full bg-emerald-600 text-white py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-100">거래처 등록</button>
            </form>
            <div className="space-y-3 max-h-48 overflow-y-auto custom-scrollbar">
              {vendorList.map(v => (
                <div key={v.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl">
                  <span className="font-bold text-sm text-slate-700">{v.name}</span>
                  <button onClick={() => setVendorList(l => l.filter(i => i.id !== v.id))} className="text-rose-400 text-[10px] font-black uppercase hover:text-rose-600">삭제</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type EntryType = '매출' | '지출';

export type CategoryType = '식자재' | '인건비' | '월세' | '관리비' | '비고정지출' | '판매수수료' | '기타매출';

export type StaffType = '정규직' | '알바';

export interface User {
  id: string;
  userId: string;
  name: string;
}

export interface Staff {
  id: string;
  name: string;
  type: StaffType;
  basePay: number; // 월급 또는 시급
}

export interface Vendor {
  id: string;
  name: string;
  contact?: string;
}

export interface FixedExpenseItem {
  id: string;
  name: string;
  defaultCategory: '월세' | '관리비' | '비고정지출';
  monthlyAmount: number; // 월 고정 금액 추가
}

export interface PLEntry {
  id: string;
  category: string;
  type: EntryType;
  amount: number;
  date: string;
  description: string;
  staffId?: string;
  vendorId?: string;
  fixedExpenseId?: string;
}

export interface PLSummary {
  totalRevenue: number;
  totalExpense: number;
  netProfit: number;
  foodCostRatio: number;
  laborCostRatio: number;
}

import React, { useState, useMemo, useEffect } from 'react';
import { PLEntry, PLSummary, Staff, Vendor, FixedExpenseItem, User } from './types';
import EntryModal from './components/EntryModal';

const INITIAL_STAFF: Staff[] = [
  { id: 's1', name: '김주방', type: '정규직', basePay: 3500000 },
  { id: 's2', name: '이서빙', type: '알바', basePay: 10500 },
];

const INITIAL_VENDORS: Vendor[] = [
  { id: 'v1', name: '프레시웨이' },
  { id: 'v2', name: '마켓보로' },
];

const INITIAL_FIXED_EXPENSES: FixedExpenseItem[] = [
  { id: 'f1', name: '매장 월세', defaultCategory: '월세', monthlyAmount: 3200000 },
  { id: 'f2', name: '공과금 통합', defaultCategory: '관리비', monthlyAmount: 650000 },
  { id: 'f3', name: '보안/인터넷', defaultCategory: '비고정지출', monthlyAmount: 120000 },
];

const INITIAL_ENTRIES: PLEntry[] = [
  { id: '1', category: '홀매출', type: '매출', amount: 1850000, date: new Date().toISOString().split('T')[0], description: '금일 점심 만석' },
  { id: '2', category: '식자재', type: '지출', amount: 320000, date: new Date().toISOString().split('T')[0], description: '야채/청과 추가 매입', vendorId: 'v1' },
];

const App: React.FC = () => {
  // 인증 관련 상태
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [authForm, setAuthForm] = useState({ userId: '', password: '', name: '' });

  // 비즈니스 데이터 상태
  const [entries, setEntries] = useState<PLEntry[]>(INITIAL_ENTRIES);
  const [staffList, setStaffList] = useState<Staff[]>(INITIAL_STAFF);
  const [vendorList, setVendorList] = useState<Vendor[]>(INITIAL_VENDORS);
  const [fixedExpenseItems, setFixedExpenseItems] = useState<FixedExpenseItem[]>(INITIAL_FIXED_EXPENSES);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isVendorModalOpen, setIsVendorModalOpen] = useState(false);
  const [isFixedExpenseModalOpen, setIsFixedExpenseModalOpen] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const thisMonthStr = todayStr.slice(0, 7);
  const currentDayOfMonth = new Date().getDate();

  // 로그인 처리
  const handleAuthSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isLoginMode) {
      // 데모용 로그인 로직: 어떤 아이디든 비번 4자리 이상이면 통과
      if (authForm.userId && authForm.password.length >= 4) {
        setCurrentUser({ id: 'u1', userId: authForm.userId, name: authForm.userId.split('@')[0] });
      } else {
        alert('아이디와 비밀번호(4자 이상)를 확인해주세요.');
      }
    } else {
      // 데모용 회원가입 로직
      if (authForm.userId && authForm.password && authForm.name) {
        alert('회원가입이 완료되었습니다. 로그인해주세요.');
        setIsLoginMode(true);
      }
    }
  };

  const handleLogout = () => {
    if (window.confirm('로그아웃 하시겠습니까?')) {
      setCurrentUser(null);
      setAuthForm({ userId: '', password: '', name: '' });
    }
  };

  const monthlyLaborFixed = useMemo(() => 
    staffList.filter(s => s.type === '정규직').reduce((acc, curr) => acc + curr.basePay, 0)
  , [staffList]);

  const monthlyFixedCostOnly = useMemo(() => 
    fixedExpenseItems.reduce((acc, curr) => acc + curr.monthlyAmount, 0)
  , [fixedExpenseItems]);

  const calculateStats = (filteredEntries: PLEntry[], days: number) => {
    const rev = filteredEntries.filter(e => e.type === '매출').reduce((acc, curr) => acc + curr.amount, 0);
    const actualExp = filteredEntries.filter(e => e.type === '지출').reduce((acc, curr) => acc + curr.amount, 0);
    const laborFixedPart = (monthlyLaborFixed / 30) * days;
    const fixedExpensePart = (monthlyFixedCostOnly / 30) * days;

    const foodEntries = filteredEntries.filter(e => e.category === '식자재');
    const laborEntries = filteredEntries.filter(e => e.category === '인건비');
    const fixedManualEntries = filteredEntries.filter(e => ['월세', '관리비'].includes(e.category));
    const otherEntries = filteredEntries.filter(e => e.type === '지출' && !['식자재', '인건비', '월세', '관리비'].includes(e.category));

    const foodCost = foodEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableLabor = laborEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const manualFixed = fixedManualEntries.reduce((acc, curr) => acc + curr.amount, 0);
    const variableOthers = otherEntries.reduce((acc, curr) => acc + curr.amount, 0);

    const totalLabor = laborFixedPart + variableLabor;
    const totalFixed = fixedExpensePart + manualFixed;
    const totalExp = actualExp + laborFixedPart + fixedExpensePart;

    return {
      rev, exp: totalExp, profit: rev - totalExp, foodCost, laborCost: totalLabor, fixedCost: totalFixed, variableOthers,
      foodRatio: rev > 0 ? (foodCost / rev) * 100 : 0,
      laborRatio: rev > 0 ? (totalLabor / rev) * 100 : 0,
      fixedRatio: rev > 0 ? (totalFixed / rev) * 100 : 0,
      othersRatio: rev > 0 ? (variableOthers / rev) * 100 : 0,
      categories: { food: { items: foodEntries, total: foodCost }, labor: { items: laborEntries, total: totalLabor, auto: laborFixedPart }, fixed: { items: fixedManualEntries, total: totalFixed, auto: fixedExpensePart }, others: { items: otherEntries, total: variableOthers } }
    };
  };

  const dashboardStats = useMemo(() => {
    const todayEntries = entries.filter(e => e.date === todayStr);
    const monthEntries = entries.filter(e => e.date.startsWith(thisMonthStr));
    return { today: calculateStats(todayEntries, 1), month: calculateStats(monthEntries, currentDayOfMonth) };
  }, [entries, todayStr, thisMonthStr, currentDayOfMonth, monthlyLaborFixed, monthlyFixedCostOnly]);

  const handleAddEntry = (entry: Omit<PLEntry, 'id'>) => {
    setEntries(prev => [...prev, { ...entry, id: Math.random().toString(36).substr(2, 9) }]);
  };

  const handleDeleteEntry = (id: string) => {
    if (window.confirm('이 내역을 삭제하시겠습니까?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  // 로그인 화면 렌더링
  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full opacity-20">
          <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-500 rounded-full blur-[120px]"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-emerald-500 rounded-full blur-[120px]"></div>
        </div>

        <div className="w-full max-w-md bg-white/10 backdrop-blur-3xl rounded-[3rem] border border-white/20 p-12 shadow-2xl relative z-10 animate-in fade-in zoom-in duration-500">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center text-slate-900 mx-auto mb-6 shadow-xl">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            </div>
            <h1 className="text-3xl font-black text-white tracking-tighter">Smart P&L Analyst</h1>
            <p className="text-slate-400 text-sm mt-2 font-medium">개별 계정으로 안전하게 경영 상태를 관리하세요.</p>
          </div>

          <form onSubmit={handleAuthSubmit} className="space-y-4">
            {!isLoginMode && (
              <input
                type="text"
                required
                placeholder="사용자 이름"
                className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                value={authForm.name}
                onChange={e => setAuthForm({...authForm, name: e.target.value})}
              />
            )}
            <input
              type="text"
              required
              placeholder="아이디 (이메일)"
