          </div>
        </div>
      </div>
    );
  }

  const CategoryAnalysisCard = ({ title, total, ratio, items, autoValue, colorClass }: { title: string, total: number, ratio: number, items: PLEntry[], autoValue?: number, colorClass: string }) => (
    <div className="flex flex-col bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
      <div className={`p-5 border-b border-slate-50 ${colorClass} bg-opacity-5`}>
