            <div className="flex items-center gap-2 ml-2"><span className="text-[11px] font-black text-rose-500">-{item.amount.toLocaleString()}</span><button onClick={() => handleDeleteEntry(item.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg></button></div>
