        <CategoryAnalysisCard title="비고정/기타" total={stats.variableOthers} ratio={stats.othersRatio} items={stats.categories.others.items} colorClass="bg-slate-500" />
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
