        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex flex-col justify-center shadow-sm"><span className="text-[10px] font-black uppercase text-slate-400 mb-1">총 지출 (고정비 포함)</span><div className="text-3xl font-black text-rose-500">-{stats.exp.toLocaleString()}원</div></div>
